insert into public.questions
  (subject_code, num, question, options, answer, answer_text, images, is_active, has_image, error_risk, error_risk_reason)
values
  ('HOD102', 1, 'Which statement is correct?(NHUNG HOÀNG)', '{"A":"The aesthetic movement appeared before the arts and crafts movement.","B":"The aesthetic movement appeared same time the arts and crafts movement","C":"The aesthetic movement appeared after the arts and crafts movement","D":"All is incorrect"}'::jsonb, 'B', 'B. The aesthetic movement appeared same time the arts and crafts movement', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 2, 'Which artistic group was founded in the Dutch city of Leiden in 1917? Check one option.', '{"A":"The Bauhaus","B":"De Stijl","C":"Constructivism","D":"The Arts and Crafts Movement"}'::jsonb, 'B', 'B. De Stijl', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 3, 'In ancient China, the ____ plow, crossbow, propeller , and magnetic compass were invented. (NHUNG HOÀNG)', '{"A":"bronze","B":"iron","C":"silver","D":"steel"}'::jsonb, 'B', 'B. iron', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 4, 'What immutable principles were laid down by the British artist William Hogarth in his book The Analysis of Beauty (published in 1753)? Check all that apply.', '{"A":"simplicity","B":"harmony","C":"nature","D":"propotion","E":"fitness"}'::jsonb, 'ADE', 'A. simplicity; D. propotion; E. fitness', '[{"id":"learninghub/questions/j3xdrxtvqeixtrasr7yp","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571914/learninghub/questions/j3xdrxtvqeixtrasr7yp.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571914/learninghub/questions/j3xdrxtvqeixtrasr7yp.webp","width":191,"format":"webp","height":191,"source":"cloudinary","public_id":"learninghub/questions/j3xdrxtvqeixtrasr7yp"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 5, 'Who was one of the greatest proponents of the Rococo style, who published a book entitled "The Gentleman and Cabinet Maker''s Director", which was lavishly illustrated with 161 engraved plates showing "elegant and useful designs of household furniture in the Gothic, Chinese and modern taste"? Check one option.', '{"A":"Thomas Chippendale","B":"Jean-Francois Leleu","C":"Thomas Sheraton","D":"Robert Adam"}'::jsonb, 'A', 'A. Thomas Chippendale', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 6, 'Which country''s designers have thoroughly applied the streamlining form less for functional reasons and more to make household products look sleeker and thereby more tempting to the customer? (NHUNG HOÀNG)', '{"A":"England.","B":"Germany.","C":"France.","D":"America."}'::jsonb, 'D', 'D. America.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 7, 'This picture shows a red-blue chair designed by Gerrit Rietveld. What style is it? Check one option. (NHUNG HOÀNG)', '{"A":"Art and Craft.","B":"De Stijl.","C":"Art Nouveau.","D":"Pop Art."}'::jsonb, 'A', 'A. Art and Craft.', '[{"id":"learninghub/questions/n3x5rrloxo0ymo1jnq84","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571916/learninghub/questions/n3x5rrloxo0ymo1jnq84.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571916/learninghub/questions/n3x5rrloxo0ymo1jnq84.webp","width":190,"format":"webp","height":189,"source":"cloudinary","public_id":"learninghub/questions/n3x5rrloxo0ymo1jnq84"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 8, 'In the mid-19th century, why did Henry Cole and Adolf Loos consider the ornament as one of the basic factors hindering the development of industrial design? (NHUNG HOÀNG)', '{"A":"Waste of labor and time.","B":"Impedes the intended function of an object.","C":"Waste of materials and energy.","D":"All of the above."}'::jsonb, 'D', 'D. All of the above.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 9, 'In addition to the Japanese influence, what other decorative motifs have been recurred in Aesthetic movement style interiors? Check one option.', '{"A":"Magnolia","B":"Sea anemones","C":"Dragon","D":"Sunflowers and peacock feathers"}'::jsonb, 'D', 'D. Sunflowers and peacock feathers', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 10, 'Vietnamese-French designer Nguyen Manh Khanh, who known as Quasar , developed the first inflatable furniture product line, in 1967. What is the name of this collection?', '{"A":"None of the answer","B":"The Fiction collection,","C":"The Future Astronaut collection","D":"The Aerospace collection"}'::jsonb, 'D', 'D. The Aerospace collection', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 11, 'What are the characteristics of the Postmodern design? (NHUNG HOÀNG)', '{"A":"Exuberantly playful, capturing the optimism, color combinations, bold overall forms.","B":"Exuberantly playful, capturing the optimism, bold overall forms.","C":"It had roots in social ideas related to health and inclusivity.","D":"It was far playful in its use of coded meanings and mixed messages."}'::jsonb, 'A', 'A. Exuberantly playful, capturing the optimism, color combinations, bold overall forms.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 12, 'How many ages in the history of development of human beings in prehistoric periods?', '{"A":"1","B":"2","C":"3","D":"4"}'::jsonb, 'C', 'C. 3', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 13, 'What was the reason for the Pop Art movement thriving in the 1960s?', '{"A":"Meet the needs of enjoying the diverse arts of popular people.","B":"Meet the novelty of commodity models in a highly competitive market.","C":"The development of new materials and manufacturing techniques, allowing machines to create richer shapes and colours.","D":"All three reasons above."}'::jsonb, 'D', 'D. All three reasons above.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 14, 'While the kind of standardization, allowing a degree of interchangeability, had been used previously to make weapons in ancient China and during the Roman period, who was the first to employ it within the context of industrial mechanization? Check one option. (NHUNG HOÀNG)', '{"A":"Eli Whitney","B":"Samuel Colt","C":"Thomas Blanchard","D":"Alexander Graham Bell"}'::jsonb, 'A', 'A. Eli Whitney', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 15, 'What did Augustus Welby Northmore Pugin (A.W.N. Pugin) design in Westminster , London?', '{"A":"Buckingham Palace","B":"Westminster Abbey","C":"The interiors of Westminster Palace","D":"The Tower of London"}'::jsonb, 'C', 'C. The interiors of Westminster Palace', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 16, 'The mass-production of weaponry perfected in American factories during the mid-nineteenth century changed the face of military conflict permanently. Which war was the first instance of this modern industrialized warfare? Check one option.(NHUNG HOÀNG)', '{"A":"Civil War of 1861-65","B":"World War I","C":"World War II","D":"None of the answer ."}'::jsonb, 'A', 'A. Civil War of 1861-65', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 17, 'Fill in the blank: By the late of nineteenth century, Germany had become a significant industrial powerhouse. However , most of this part was based on the processes that had been borrowed from British. The products was ....with ....quality.', '{"A":"Cheap ... low","B":"Expensive...good","C":"Expensive....low"}'::jsonb, 'A', 'A. Cheap ... low', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 18, 'What kind of materials did British designers and engineers use when facing difficulties due to the scarcity of raw materials in postwar Britain?', '{"A":"Any material they can find.","B":"Plastic.","C":"Wood.","D":"Steel."}'::jsonb, 'A', 'A. Any material they can find.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 19, 'For a period of roughly eighty years of seismic social and political change - from around 1750- to 1830 - Neoclassism was the dominant style in art, architecture, and design. While in England it is most commonly referred to as Georgian or Regency, in France Neoclassism became known as Empire style. In America, what another name was Neoclassism called, thanks to its political connotation?(NHUNG HOÀNG)', '{"A":"Gustavian style","B":"Directoire style","C":"Mannerist style","D":"Federal style"}'::jsonb, 'D', 'D. Federal style', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 20, 'For a period of roughly eighty years of seismic social and political change from around 1750 to 1830, what style was dominant style in art, architecture and design?(NHUNG HOÀNG)', '{"A":"Art Deco","B":"Art Nouveau","C":"Baroque","D":"Neoclassicism"}'::jsonb, 'D', 'D. Neoclassicism', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 21, 'In 1973, what crisis prompted US carmakers to explore more "compact" fuel-efficient cars?', '{"A":"Resources.","B":"Oil crisis.","C":"Economic crisis.","D":"Labour resources."}'::jsonb, 'B', 'B. Oil crisis.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 22, 'In the late of 1960s and 1970s, many designers looked to the future optimistically and created products for an age in which everything would be shiny, clean, and bright; the visions they conjured offered a much-needed respite from the Vietnam War and other earthbound troubles. What kind of design movement is mentioned above?', '{"A":"Plastic age.","B":"Design goes pop.","C":"Space-Age visions","D":"Postmodernism."}'::jsonb, 'C', 'C. Space-Age visions', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 23, 'Fill in the blank: During the postwar years, another aspect of American design evolved out of wartime research into "human factors": called ....', '{"A":"Designing for People","B":"Anthropometric Design","C":"Organic design","D":"Italian design"}'::jsonb, 'B', 'B. Anthropometric Design', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 24, 'Which event in 1925 helped solidify the prominence of Art Deco and also showcased early Check one option.', '{"A":"Exposition Universelle","B":"International Hygiene Exhibition","C":"Exposition Internationale des Arts Décoratifs et Industriels Modernes","D":"Weissenhof Housing Exhibition"}'::jsonb, 'C', 'C. Exposition Internationale des Arts Décoratifs et Industriels Modernes', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 25, 'In the 1920s, who realized that aesthetics would play an increasingly important role over the coming years in differentiating products?(NHUNG HOÀNG)', '{"A":"General Motors chairman Alfred Sloan","B":"Adolf Loos","C":"William Hogarth","D":"Henry Cole"}'::jsonb, 'A', 'A. General Motors chairman Alfred Sloan', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 26, 'What are the main causes of German industry development? Check two options.', '{"A":"Aesthetic response to the Industrial Revolution.","B":"Germany yearned for a strong and powerful state.","C":"The level of educational attainment among citizens is high.","D":"Advertising boomed."}'::jsonb, 'BC', 'B. Germany yearned for a strong and powerful state.; C. The level of educational attainment among citizens is high.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 27, 'Who were the founders of Britain''s first important Arts and Crafts group, the Century Guild of Artists?', '{"A":"William Morris and Charles Voysey","B":"Arthur Heygate Mackmurdo and Selwyn Image","C":"Eliel Saarinen and Charles Rennie Mackintosh","D":"Elias Lönnrot and Holm Hansen Munthe"}'::jsonb, 'B', 'B. Arthur Heygate Mackmurdo and Selwyn Image', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 28, 'What were a number of other military designs first appeared during World War I?', '{"A":"chemical weapons such as mustard gas, biplanes used for bombing","B":"aerial reconnaissance, submarines","C":"tanks","D":"All of the answers."}'::jsonb, 'D', 'D. All of the answers.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 29, 'In 1949, it was the most famous house (1949) - now better known as the Eames House-in Pacific Palisades, the self-designed home of Charles and Ray Eames. What is the name of this house?', '{"A":"Case Study House No. 6","B":"Case Study House No. 7","C":"Case Study House No. 8","D":"Case Study House No. 9"}'::jsonb, 'C', 'C. Case Study House No. 8', '[{"id":"learninghub/questions/q55zk28rhibh62kridxc","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571917/learninghub/questions/q55zk28rhibh62kridxc.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571917/learninghub/questions/q55zk28rhibh62kridxc.webp","width":190,"format":"webp","height":108,"source":"cloudinary","public_id":"learninghub/questions/q55zk28rhibh62kridxc"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 30, 'This picture shows an image of the side chair designed by Harvey Ellis for Gustav Stickley, c. 1903. What style is this? (NHUNG HOÀNG)', '{"A":"Neoclassicism","B":"Bauhaus","C":"Arts and Crafts movement in Britain","D":"Arts and Crafts movement in American"}'::jsonb, 'D', 'D. Arts and Crafts movement in American', '[{"id":"learninghub/questions/zfivo1eq5cj8jllxjgre","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571918/learninghub/questions/zfivo1eq5cj8jllxjgre.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571918/learninghub/questions/zfivo1eq5cj8jllxjgre.webp","width":137,"format":"webp","height":214,"source":"cloudinary","public_id":"learninghub/questions/zfivo1eq5cj8jllxjgre"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 31, 'This picture shows an image of the interior of the Osterreichische Postparkasse (Austrian Postal Savings Bank) in Vienna designed by Otto Wagner , 1906. What style is this?', '{"A":"Vienna Secession","B":"Bauhaus","C":"Destijl","D":"Constructivism"}'::jsonb, 'A', 'A. Vienna Secession', '[{"id":"learninghub/questions/nazxcxuxbp8no3t233zl","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571919/learninghub/questions/nazxcxuxbp8no3t233zl.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571919/learninghub/questions/nazxcxuxbp8no3t233zl.webp","width":192,"format":"webp","height":126,"source":"cloudinary","public_id":"learninghub/questions/nazxcxuxbp8no3t233zl"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 32, 'This picture shows an image of the Finnish Pavilion designed by the architect Eliel Saarinen, perhaps Finland''s greatest exponent of National Romanticism, who pioneered a style of architecture and design that alluded to his country''s ancient Karelian culture. Where the motifs on this building inspired?', '{"A":"Viking-revival style","B":"Dragon motifs","C":"Nature","D":"Nordic folk art and vernacular architecture"}'::jsonb, 'D', 'D. Nordic folk art and vernacular architecture', '[{"id":"learninghub/questions/kjpigeydremjq7mdng4o","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571920/learninghub/questions/kjpigeydremjq7mdng4o.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571920/learninghub/questions/kjpigeydremjq7mdng4o.webp","width":160,"format":"webp","height":204,"source":"cloudinary","public_id":"learninghub/questions/kjpigeydremjq7mdng4o"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 33, 'This picture shows an image of the Viking-revival armchair designed by Lars Kinsarvik that revealed a romantic notion of Norway''s past with the motif of Dragon. What style was it designed?', '{"A":"Classicism","B":"Neo-Classicism","C":"Modernism","D":"National Romanticism"}'::jsonb, 'D', 'D. National Romanticism', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 34, 'This picture shows an image of a highly innovative chair designed by Arthur Heygate Mackmurdo for the guild''s dining hall that featured a back splat incorporating an asymmetrical motif of swirling foliage stems. What style was it designed?', '{"A":"Arts and Crafts movement in Britain","B":"Arts and Crafts movement in America","C":"Aesthetic movement","D":"Neo-classicism"}'::jsonb, 'A', 'A. Arts and Crafts movement in Britain', '[{"id":"learninghub/questions/pyalmyhlfjedkf4fjcvg","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571922/learninghub/questions/pyalmyhlfjedkf4fjcvg.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571922/learninghub/questions/pyalmyhlfjedkf4fjcvg.webp","width":225,"format":"webp","height":240,"source":"cloudinary","public_id":"learninghub/questions/pyalmyhlfjedkf4fjcvg"},{"id":"learninghub/questions/n6vk28qutsyp3xg2bttk","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571923/learninghub/questions/n6vk28qutsyp3xg2bttk.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571923/learninghub/questions/n6vk28qutsyp3xg2bttk.webp","width":168,"format":"webp","height":202,"source":"cloudinary","public_id":"learninghub/questions/n6vk28qutsyp3xg2bttk"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 35, 'This picture shows an image of the interior of the Dana Thomas House in Springfield, Illinois, that the architect took an enormous care in the minute detailing of his building, and more than any other individual he bridged the transition between the Arts and Crafts movement and the later International Style through his unified architectural schemes. Who is the architect mentioned above?', '{"A":"Ludwig Mies Van der Rohe","B":"Frank Lloyd Wright","C":"Le Corbusier","D":"Walter Gropius"}'::jsonb, 'B', 'B. Frank Lloyd Wright', '[{"id":"learninghub/questions/wpe6gvwtcmh5qqft9iqx","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571924/learninghub/questions/wpe6gvwtcmh5qqft9iqx.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571924/learninghub/questions/wpe6gvwtcmh5qqft9iqx.webp","width":190,"format":"webp","height":143,"source":"cloudinary","public_id":"learninghub/questions/wpe6gvwtcmh5qqft9iqx"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 36, 'This picture shows an image of the Salon of Victor Horta''s house and studio in Brussels (now the Horta Museum), designed in 1898. What style is this?', '{"A":"Aesthetic movement","B":"Art Deco","C":"High Victorian style","D":"Art Nouveau"}'::jsonb, 'D', 'D. Art Nouveau', '[{"id":"learninghub/questions/t4vcblptmk0mjaapxbtj","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571926/learninghub/questions/t4vcblptmk0mjaapxbtj.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571926/learninghub/questions/t4vcblptmk0mjaapxbtj.webp","width":190,"format":"webp","height":123,"source":"cloudinary","public_id":"learninghub/questions/t4vcblptmk0mjaapxbtj"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 37, 'This picture shows an image of the Sagrada Familia church, a very famous Art Nouveau building in Barcelona. The architect borrowed motifs from Gothic and Moorish architecture and then transformed them into exotic melting forms that made it looks like a fanciful fairy-tale castle out of sand. Who is the author of this work?', '{"A":"Hector Guidmard","B":"Henry van de Velde","C":"Frank Lloyd Wright","D":"Antonio Gaudi"}'::jsonb, 'D', 'D. Antonio Gaudi', '[{"id":"learninghub/questions/gblw2mijvrubtatyw0pp","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571927/learninghub/questions/gblw2mijvrubtatyw0pp.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571927/learninghub/questions/gblw2mijvrubtatyw0pp.webp","width":140,"format":"webp","height":208,"source":"cloudinary","public_id":"learninghub/questions/gblw2mijvrubtatyw0pp"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 38, 'This picture shows an image of the objects produced and exhibited at the Great Exhibition of all Nations, 1851. This so called "fancy goods" were for the most part revivalist wares whose decoration teemed with references to every previous style in history, from Rococo, Baroque, and Neoclassical, to the more unusual Assyrian, Eritrean, and Celtic. What is the name of this style?', '{"A":"Mannerist style","B":"High Victorian style","C":"Empire style","D":"Queen Anne revival style"}'::jsonb, 'B', 'B. High Victorian style', '[{"id":"learninghub/questions/s3llppmp7eoxa1c18bss","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571928/learninghub/questions/s3llppmp7eoxa1c18bss.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571928/learninghub/questions/s3llppmp7eoxa1c18bss.webp","width":144,"format":"webp","height":207,"source":"cloudinary","public_id":"learninghub/questions/s3llppmp7eoxa1c18bss"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 39, 'This picture show an image of an adjustable chair designed by Philip Webb,', '{"A":"Rocco style","B":"High Victorian style","C":"Art Nouveau style","D":"Arts and Crafts movement"}'::jsonb, 'D', 'D. Arts and Crafts movement', '[{"id":"learninghub/questions/tjjftqmsddxrcgojk4h3","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571929/learninghub/questions/tjjftqmsddxrcgojk4h3.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571929/learninghub/questions/tjjftqmsddxrcgojk4h3.webp","width":152,"format":"webp","height":205,"source":"cloudinary","public_id":"learninghub/questions/tjjftqmsddxrcgojk4h3"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 40, 'This picture shows an image of a sideboard created by William Godwin in accordance with fashionable taste which captured the spirit of Japan by referencing Japanese motifs and constructions while remaining at the same time very much British "art furniture". What style is this?', '{"A":"Aesthetic movement","B":"Arts and Crafts movement","C":"Art Deco","D":"The New Art"}'::jsonb, 'A', 'A. Aesthetic movement', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 41, 'This picture show an image of a research drawing into botanical structural form and the insightful understanding of the art of Japan. Who is the author of this sketch?', '{"A":"Edward William Godwin","B":"Christopher Dresser","C":"A. W. N. Pugin","D":"Edward Burne-Jones"}'::jsonb, 'B', 'B. Christopher Dresser', '[{"id":"learninghub/questions/eni8biooderlkfwgpcgt","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571930/learninghub/questions/eni8biooderlkfwgpcgt.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571930/learninghub/questions/eni8biooderlkfwgpcgt.webp","width":231,"format":"webp","height":85,"source":"cloudinary","public_id":"learninghub/questions/eni8biooderlkfwgpcgt"},{"id":"learninghub/questions/hchrdmivimxcablreqyu","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571931/learninghub/questions/hchrdmivimxcablreqyu.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571931/learninghub/questions/hchrdmivimxcablreqyu.webp","width":141,"format":"webp","height":208,"source":"cloudinary","public_id":"learninghub/questions/hchrdmivimxcablreqyu"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 42, 'This picture shows an image of a well-known Model No.2274 lozenge-shape teapot, designed by Christopher Dresser and for James Dixon & Sons in 1879. Where was this object inspired?(073-356-8678)', '{"A":"Queen Anne revival-style","B":"Anglo-Japanese","C":"Moorish-inspired furniture","D":"The element geometric formalism found in Japanese design"}'::jsonb, 'D', 'D. The element geometric formalism found in Japanese design', '[{"id":"learninghub/questions/pjoafesq4ftrnkpk3wjj","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571932/learninghub/questions/pjoafesq4ftrnkpk3wjj.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571932/learninghub/questions/pjoafesq4ftrnkpk3wjj.webp","width":190,"format":"webp","height":147,"source":"cloudinary","public_id":"learninghub/questions/pjoafesq4ftrnkpk3wjj"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 43, 'The Michael Thonet''s classic café chair , the Model No.14 (image below), with its double-looped back, was essentially a form that was stripped of all superfluous ornamentation. Every element of its steam-bent frame and its caned or molded plywood seat was essential for its function: no more, no less. What style was this chair designed?', '{"A":"Minimalism","B":"Modernism","C":"Classicism","D":"Biedermeier"}'::jsonb, 'D', 'D. Biedermeier', '[{"id":"learninghub/questions/doa4zm30ztupcwazrgs2","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571933/learninghub/questions/doa4zm30ztupcwazrgs2.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571933/learninghub/questions/doa4zm30ztupcwazrgs2.webp","width":147,"format":"webp","height":207,"source":"cloudinary","public_id":"learninghub/questions/doa4zm30ztupcwazrgs2"}]'::jsonb, true, true, 'low', null),
  ('HOD102', 44, 'This picture shows an image of the "Klismos" chair (designed by Nicolai Abraham) which based on ancient Greek precedents, had an outstanding, almost modern structural simplicity. What style was it designed?', '{"A":"Baroque","B":"Rococo","C":"Renaissance","D":"Neo-classicism"}'::jsonb, 'D', 'D. Neo-classicism', '[{"id":"learninghub/questions/ctspt67j8yixsuk5lwho","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571934/learninghub/questions/ctspt67j8yixsuk5lwho.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571934/learninghub/questions/ctspt67j8yixsuk5lwho.webp","width":197,"format":"webp","height":171,"source":"cloudinary","public_id":"learninghub/questions/ctspt67j8yixsuk5lwho"}]'::jsonb, true, true, 'low', null),
