  ('HOD102', 51, 'When did the digital era had truly begun with the release of the original Apple Macintosh desktop computer , conceived by a youthful Steve Jobs as a $500 product?', '{"A":"January 1983","B":"January 1984","C":"January 1985","D":"January 1990"}'::jsonb, 'B', 'B. January 1984', '[]'::jsonb, true, false, 'low', null),
