  ('HOD102', 62, 'In ancient societies, the design of tools and implements was primarily influenced by:... Check one option.', '{"A":"Functional requirements and raw material availability.","B":"Artistic trends of the era.","C":"The personal preference of the ruling class.","D":"Religious and ceremonial needs."}'::jsonb, 'A', 'A. Functional requirements and raw material availability.', '[]'::jsonb, true, false, 'low', null),
