  ('HOD102', 67, 'This is an amphora, a type of pottery of ancient Romans. What are the most striking features of this ceramic vase? Check one option.', '{"A":"Easy carrying and pouring. thanks to its looping handles and long","B":"Large capacity, allowing to contain a large amount of olive oil, wine","C":"All of the answers","D":"Thick ceramic material, the glossy glaze can be easily cleaned, good hygiene, quality assurance, taste for olive oil, wine and garum for a long time."}'::jsonb, 'A', 'A. Easy carrying and pouring. thanks to its looping handles and long', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 68, 'What method of production has been used to make the most beautiful prehistoric ceramics come from Ban Chiang area in north-eastern Thailand?', '{"A":"Paddle and anvil.","B":"Turntable.","C":"Molds made of bamboo.","D":"Plaster molds."}'::jsonb, 'A', 'A. Paddle and anvil.', '[{"id":"learninghub/questions/ssik6xj3nut3qrtomodq","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571941/learninghub/questions/ssik6xj3nut3qrtomodq.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571941/learninghub/questions/ssik6xj3nut3qrtomodq.webp","width":145,"format":"webp","height":174,"source":"cloudinary","public_id":"learninghub/questions/ssik6xj3nut3qrtomodq"}]'::jsonb, true, true, 'low', null),
