  ('HOD102', 70, 'In the ___ century, the improved water wheel allowed water power to be harnessed into energy to mill flour , saw wood, and cleanse woolen cloth of impurities.', '{"A":"9th","B":"10th","C":"7th","D":"8th"}'::jsonb, 'C', 'C. 7th', '[{"id":"learninghub/questions/qucfsbsijuwctnrelpts","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571942/learninghub/questions/qucfsbsijuwctnrelpts.webp","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782571942/learninghub/questions/qucfsbsijuwctnrelpts.webp","width":196,"format":"webp","height":204,"source":"cloudinary","public_id":"learninghub/questions/qucfsbsijuwctnrelpts"}]'::jsonb, true, true, 'low', null),
