  ('HOD102', 72, 'Which of the following represents the characteristics of Rococo style?', '{"A":"Popular (designed for the majority)","B":"Charming, delicate, overtly feminine, sumptuously opulent","C":"Heavy, florid, dramatic.","D":"Aesthetic, technical and cheap."}'::jsonb, 'B', 'B. Charming, delicate, overtly feminine, sumptuously opulent', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 73, 'What are the enlightenments?', '{"A":"The age of reason","B":"A cultural movement of intellectuals in 16th century in Europe","C":"Mobilize the power of reason to reform society and advance knowledge","D":"Challenged age-old religious dogma and promoted scientific knowledge, industrial progress."}'::jsonb, 'ACD', 'A. The age of reason; C. Mobilize the power of reason to reform society and advance knowledge; D. Challenged age-old religious dogma and promoted scientific knowledge, industrial progress.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 74, 'Which manufacturer demonstrated for the first time that machinery and its logical implemetation could unequivocally make designs that were not only better in quality but also capable of being produced on a much larger scale and much more cheaply - a wining outcome not only for the Royal Navy but indeed for any canny manufacturer of goods interest in turning a larger profit? Check one option.', '{"A":"Coalbrookdale","B":"Wedgwood","C":"Portsmouth Block Mills","D":"Danhauser Furniture Factory"}'::jsonb, 'C', 'C. Portsmouth Block Mills', '[]'::jsonb, true, false, 'low', null),
