  ('HOD102', 82, 'It was a style that looked optimistically to the future rather than nostalgically to the past, using as its primary source of inspiration the visually seductive and tactile forms of the natural world. It was also a truly international style that was adopted comprehensively across all realms of the applied arts: from glassware, furniture, and lighting to jewelry, graphic design, and typography. What is this style? Check one option', '{"A":"Neo Classicism","B":"De Stijl","C":"Art Nouveau","D":"Organic design"}'::jsonb, 'C', 'C. Art Nouveau', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 83, 'What was the outcome of the Dresden Exhibition for the German Arts and Crafts movement? Check one option.', '{"A":"It led to the discontinuation of the movement","B":"It showcased a shift towards functionality in design over artistic expressiveness","C":"It focused on reintroducing historical art styles","D":"It emphasized the need for more ornamental arts education"}'::jsonb, 'B', 'B. It showcased a shift towards functionality in design over artistic expressiveness', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 84, 'What work of Adolf Loos has marked an intellectual turning point that led to a complete rejection of decorative motifs and towards a purely functional style?', '{"A":"Studies in Design.","B":"Ornament and Crime.","C":"Arches Warenbüch.","D":"Principles Decorative Design."}'::jsonb, 'B', 'B. Ornament and Crime.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 85, 'What are the characteristics of De Stijl movement? Check one option.', '{"A":"Considering ornament is a crime.","B":"A rational new world would emerge from geometrically symbolic art.","C":"Art must be associated with function.","D":"All of the above."}'::jsonb, 'D', 'D. All of the above.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 86, 'Like De Stijl, Constructivism had distinctly utopian goals and sought to bring about new social order by introducing a fresh formal language in art and design. Where did "Constructivism" movement come from?', '{"A":"Poland","B":"Italy","C":"Russia.","D":"Germany."}'::jsonb, 'C', 'C. Russia.', '[]'::jsonb, true, false, 'low', null),
