  ('HOD102', 148, 'The Pope Manufacturing Company achieved impressive production rates in the late nineteenth century thanks to its adoption of armory practice? Which product was considered as iconic of this American firm?', '{"A":"The Type writer","B":"The Sewing machine","C":"The Kodak Brownie camera","D":"The bicycle"}'::jsonb, 'D', 'D. The bicycle', '[]'::jsonb, true, false, 'low', null),
