  ('HOD102', 218, 'What is the De Stijl?', '{"A":"The international phenomenon that played a key role in the story of design.","B":"The art and design reform movement, in that it sought divine meaning within the mysteries of the universe through the purification of form.","C":"The style that looked optimistically to the future rather than nostalgically to the past, using as its primary source of inspiration the visually seductive and tactile forms of the natural world.","D":"The style found its most sublime expression, with examples including the extraordinary Gesamtkunstwerk (meaning \"total work of art\")"}'::jsonb, 'B', 'B. The art and design reform movement, in that it sought divine meaning within the mysteries of the universe through the purification of form.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 219, 'What is the inspiration of Memphis structure?', '{"A":"The insect.","B":"The smiotics, the study of language and symbols","C":"The flora and fauna","D":"The animal."}'::jsonb, 'B', 'B. The smiotics, the study of language and symbols', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 220, 'What does it mean for the term "Italian Line"?', '{"A":"Focus on styling rather than technology.","B":"Focus on technology rather than styling.","C":"Focus only on the function of the designs .","D":"Focus on the manufacture of the designs."}'::jsonb, 'A', 'A. Focus on styling rather than technology.', '[]'::jsonb, true, false, 'low', null),
