  ('HOD102', 224, 'What are the characteristics of High Victorian style?', '{"A":"Boasting a dramatic grid-like construction of strong vertical and horizontal elements inspired by Japanese screens.","B":"The designs were emblazoned with autograph-a very early example of an artistic signature used to sell a designed product.","C":"Harnessing the potential of mass production to create beautiful, useful","D":"Heavy ornamentation was, for the most part, the order of the day, especially in goods destined for the consumer market."}'::jsonb, 'D', 'D. Heavy ornamentation was, for the most part, the order of the day, especially in goods destined for the consumer market.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 225, 'What are the principles of timeless beauty established by William Hogarth? Check two options.', '{"A":"In relation to designing practice, the notions of fitness - \"the first fundamental law in nature with regard to beauty\".","B":"Simplicity is the most important.","C":"The proportion \"a just symmetry and harmony of parts with respect to the whole\".","D":"Beauty comes from the harmonious ratio of measurements."}'::jsonb, 'AC', 'A. In relation to designing practice, the notions of fitness - "the first fundamental law in nature with regard to beauty".; C. The proportion "a just symmetry and harmony of parts with respect to the whole".', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 226, 'Which manufacturer pioneered the mass production of consumer goods, invented the first railroad tracks for railroads, the first iron boat and the first iron bridge during the Industrial Revolution?', '{"A":"Coalbrookdale.","B":"Portsmouth Block Mills.","C":"Wedgwood.","D":"Whitneyville."}'::jsonb, 'A', 'A. Coalbrookdale.', '[]'::jsonb, true, false, 'low', null),
