  ('HOD102', 228, 'In design, what does Gesamtkunstwerk mean?', '{"A":"Total work of art.","B":"The simplicity and functionality as the most important aspects of life-enhancing design.","C":"The use of strong vertical and horizontal lines and plain, often unadorned surfaces.","D":"Restore building, decoration, glass-painting, pottery, wood-carving and metal to their rightful places beside painting and sculpture."}'::jsonb, 'A', 'A. Total work of art.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 229, 'What are the characteristics of the Aesthetic Movement? Check two options.', '{"A":"Essentially a cult of beauty, it was culturally aspirational and international.","B":"Function and underlying symbolism.","C":"Design optimized for industrial production process.","D":"Remove all decorative motifs."}'::jsonb, 'AB', 'A. Essentially a cult of beauty, it was culturally aspirational and international.; B. Function and underlying symbolism.', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 230, 'Why did plastic become the design material that designers liked most from 1963 to 1973?', '{"A":"Plastics democraticized avant-garde design, making it so affordable that for the first time in history it became part of the mass market.","B":"Plastic is a limited material in color, but it is cheap, easy to mass produce, it becomes part of the mass market.","C":"Plastic is a relatively expensive material but is easy to manufacture according to the standard process, so the product is affordable, it becomes part of the mass market.","D":"Plastic is a relatively inexpensive but colorful material that attracts young people, so it easily sells to the market at a high price, with great profits."}'::jsonb, 'A', 'A. Plastics democraticized avant-garde design, making it so affordable that for the first time in history it became part of the mass market.', '[]'::jsonb, true, false, 'low', null),
