  ('HOD102', 279, 'Which class benefited the most from the first industrial revolution whose found prosperity in the growing cities through a mercantile endeavor or civil services, or by being engaged in a profession, such as medicine and law?', '{"A":"The Upper Class","B":"The Middle Class","C":"The Lower Class","D":"The Royal Class"}'::jsonb, 'B', 'B. The Middle Class', '[]'::jsonb, true, false, 'low', null),
  ('HOD102', 280, 'Aesthetic movement was a branch of design reform that stemmed from the Gothic revival and the Pre-Raphaelite Brotherhood which was spurred on the idea of "art for art sake" rather than "craft for craft sake", and also looked further afield for decidedly more exotic inspirations instead of looking for to national vernacular precedents for design archetypes. Which was the country that influenced the most for the Aesthetes and gave the British designers, artist and architects the first taste of a design culture that had evolved along very different lines from those in Europe?', '{"A":"China","B":"Arabic","C":"Turkey","D":"Japan"}'::jsonb, 'D', 'D. Japan', '[]'::jsonb, true, false, 'low', null),
