  ('MLN111', 34, 'Tồn tại xã hội là gì?', '{"A":"Sinh hoạt vật chất và những điều kiện sinh hoạt vật chất của xã hội","B":"Toàn bộ các giá trị tinh thần của xã hội","C":"Toàn bộ các điều kiện sinh hoạt của xã hội","D":"Toàn bộ hệ tư tưởng về sự tồn tại của xã hội"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 35, 'Theo quan điểm của triết học Mác - Lênin, mối quan hệ giữa tồn tại xã hội và ý thức xã hội thể hiện như thế nào?', '{"A":"Ý thức xã hội quyết định tồn tại xã hội; tồn tại xã hội có tính độc lập tương đối, tác động trở lại ý thức xã hội","B":"Tồn tại xã hội quyết định ý thức xã hội; ý thức xã hội có tính độc lập tương đối, tác động trở lại tồn tại xã hội","C":"Tồn tại xã hội và ý thức xã hội tồn tại độc lập, không liên quan gì đến nhau","D":"Tồn tại xã hội quyết định tồn tại xã hội, ý thức xã hội quyết định ý thức xã hội"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 36, 'Theo quan điểm của triết học Mác - Lênin, “tồn tại xã hội" bao gồm những yếu tố nào?', '{"A":"Dân số, ý thức xã hội, kiến trúc thượng tầng","B":"Lực lượng sản xuất, dân số, phương thức sản xuất, ý thức xã hội","C":"Môi trường tự nhiên, quan hệ sản xuất, tâm lý xã hội, hệ tư tưởng","D":"Môi trường tự nhiên, dân số, phương thức sản xuất"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 37, 'Theo quan điểm chủ nghĩa duy vật lịch sử, lực lượng cơ bản nhất trong quần chúng nhân dân là gì?', '{"A":"Giai cấp thống trị xã hội","B":"Tầng lớp trí thức","C":"Người lao động","D":"Công nhân và nông dân"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 38, 'Quan điểm tiến bộ và cách mạng nhất của chủ nghĩa Mác - Lênin về vấn đề con người là gì?', '{"A":"Giải thích được nguồn gốc tự nhiên và xã hội của con người dưới ánh sáng khoa học","B":"Mô tả được quá trình hoạt động sống và lao động sản xuất của con người theo tinh thần của chủ nghĩa duy vật","C":"Đưa ra được học thuyết cách mạng và triệt để về đấu tranh giải phóng con người","D":"Giải thích được một cách khoa học nguồn gốc của ý thức của con người"}'::jsonb, 'C', 'C. Đưa ra được học thuyết cách mạng và triệt để về đấu tranh giải phóng con người', '[{"id":"learninghub/questions/Right_j0mphb","src":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782667517/learninghub/questions/Right_j0mphb.jpg","url":"https://res.cloudinary.com/ddc4uvm7m/image/upload/v1782667517/learninghub/questions/Right_j0mphb.jpg","width":452,"height":1762,"source":"cloudinary","public_id":"learninghub/questions/Right_j0mphb"}]'::jsonb, true, true, 'low', null),
  ('MLN111', 39, 'Theo quan điểm của chủ nghĩa Mác - Lênin, khái niệm nào dùng để chỉ lực lượng sản xuất cơ bản của xã hội, trực tiếp sản xuất ra của cải vật chất, là cơ sở của sự tồn tại và phát triển của xã hội, là động lực cơ bản của mọi cuộc cách mạng xã hội và là người sáng tạo ra những giá trị văn hóa tinh thần cho xã hội?', '{"A":"Quần chúng nhân dân","B":"Giai cấp nông dân","C":"Lãnh tụ","D":"Công nhân"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 40, 'Từ định nghĩa con người của Ph. Ăngghen, đặc điểm nào sau đây cho thấy con người khác với động vật?', '{"A":"Biết tư duy","B":"Biết ứng xử theo các quy phạm đạo đức","C":"Chính trị","D":"Biết chế tạo và sử dụng công cụ lao động"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 41, 'Trong xã hội Ấn Độ cổ đại, triết học được hiểu là:', '{"A":"Con đường suy ngẫm để dẫn dắt con người tới lẽ phải","B":"Con đường tu tập","C":"Con đường giải thoát","D":"Con đường giác ngộ"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 42, 'Triết học ra đời vào thời gian nào?', '{"A":"Thế kỷ II TCN","B":"Thế kỷ VIII - VI TCN","C":"Thế kỷ II sau CN","D":"Thế kỷ VII - VI TCN"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 43, 'Vấn đề giai cấp ở Việt Nam hiện nay như thế nào?', '{"A":"Còn đấu tranh giai cấp","B":"Không còn đấu tranh giai cấp","C":"Có sự mâu thuẫn đối kháng giai cấp","D":"Đấu tranh giai cấp gay gắt"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 44, 'Định nghĩa của V.I Lênin về giai cấp là những tập đoàn người to lớn có sự phân biệt về:', '{"A":"Địa vị của họ trong một hệ thống sản xuất xã hội nhất định trong lịch sử","B":"Địa vị của họ trong quá trình quản lý và phân phối của cải xã hội","C":"Địa vị của họ trong quản lý chính trị, văn hóa và xã hội","D":"Địa vị của họ trong việc nắm quyền lực nhà nước"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
