  ('MLN111', 46, 'Triết học Mác là thế giới quan khoa học của giai cấp nào?', '{"A":"Giai cấp tư sản tiến bộ","B":"Giai cấp công nhân","C":"Tầng lớp trí thức","D":"Giai cấp lao động"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
