  ('MLN111', 48, 'Trong hoạt động nhận thức, cần nhìn nhận sự vật trong trạng thái vận động và phát triển. Điều đó dựa trên cơ sở lý luận của nguyên lý nào?', '{"A":"Nguyên lý về mối liên hệ phổ biến","B":"Nguyên lý về sự phát triển","C":"Nguyên lý về tính thống nhất vật chất của thế giới"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 49, 'Nhận thức lý tính được thực hiện dưới hình thức nào?', '{"A":"Cảm giác, tri giác và phán đoán","B":"Khái niệm, phán đoán và suy lý","C":"Cảm giác, khái niệm, suy lý","D":"Cảm giác, tri giác, biểu tượng"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 50, 'Quy luật về sự phù hợp giữa quan hệ sản xuất với trình độ của lực lượng sản xuất nói về điều gì?', '{"A":"Quy luật này vạch rõ sự phụ thuộc khách quan của lực lượng sản xuất vào quan hệ sản xuất","B":"Sự hình thành, biến đổi và phát triển của quan hệ sản xuất được quyết định bởi lực lượng sản xuất","C":"Lực lượng sản xuất và quan hệ sản xuất là hai mặt của phương thức sản xuất, chúng tồn tại tách rời nhau","D":"Quy luật này chỉ tồn tại trong một vài xã hội"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 51, '“Cái cối xay quay bằng tay đưa lại xã hội có lãnh chúa phong kiến, cái cối xay chạy bằng máy hơi nước đưa lại xã hội có nhà tư bản công nghiệp”. Thí dụ có hình ảnh trên nhằm nêu bật vai trò quyết định, xét đến cùng, trong sự phát triển là yếu tố nào?', '{"A":"Đối tượng lao động","B":"Lực lượng sản xuất","C":"Tư liệu sản xuất","D":"Công cụ lao động"}'::jsonb, 'D', 'D. Công cụ lao động', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 52, 'Theo quan điểm duy vật lịch sử, nguồn gốc sâu xa của các cuộc cách mạng là do đâu?', '{"A":"Mâu thuẫn giai cấp","B":"Quần chúng lao động hiểu được lý luận chính trị","C":"Giai cấp cầm quyền bị khủng hoảng về đường lối cai trị","D":"Mâu thuẫn gay gắt giữa lực lượng sản xuất và quan hệ sản xuất"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 53, 'Lơxíp và Đêmôcrit có điểm chung là gì?', '{"A":"Cả hai ông đều cho rằng, vật chất là nước","B":"Cả hai ông đều cho rằng, vật chất là lửa","C":"Cả hai ông đều cho rằng, vật chất là không khí","D":"Cả hai ông đều cho rằng, vật chất là nguyên tử"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 54, 'Theo quan điểm của chủ nghĩa duy vật biện chứng thì thông qua vận động mà các dạng cụ thể của vật chất:', '{"A":"Tạo ra ý thức","B":"Không tồn tại","C":"Mất dần đi","D":"Biểu hiện"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
