  ('MLN111', 57, 'Trình độ phát triển của phương thức sản xuất ra của cải vật chất là nhân tố giữ vai trò quyết định gì?', '{"A":"Đời sống tinh thần của xã hội","B":"Đời sống văn hóa của xã hội","C":"Đời sống chính trị, đạo đức của xã hội","D":"Trình độ phát triển của nền sản xuất xã hội"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
