  ('MLN111', 59, 'Theo quan điểm của chủ nghĩa duy vật biện chứng, luận điểm nào sau đây là đúng?', '{"A":"Có tất nhiên thuần túy tồn tại khách quan","B":"Có ngẫu nhiên thuần túy tồn tại khách quan","C":"Không có cái tất nhiên và ngẫu nhiên thuần túy tồn tại bên ngoài nhau","D":"Tất nhiên và ngẫu nhiên cùng tồn tại song song với nhau trong tư duy"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 60, 'Theo quan điểm của chủ nghĩa duy vật lịch sử, lực lượng chủ thể sáng tạo ra lịch sử là ai?', '{"A":"Quần chúng nhân dân","B":"Vĩ nhân, lãnh tụ","C":"Tầng lớp trí thức","D":"Trí thức, vĩ nhân"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 61, 'Vai trò nào sau đây không phải vai trò lãnh tụ đối với phong trào của quần chúng nhân dân?', '{"A":"Thúc đẩy hoặc kìm hãm sự tiến bộ của xã hội","B":"Là người sáng lập ra các tổ chức chính trị, xã hội và là linh hồn của các tổ chức đó","C":"Lãnh tụ của mỗi thời đại chỉ có thể hoàn thành những nhiệm vụ đặt ra của thời đại đó","D":"Phát minh ra công cụ lãnh đạo quần chúng"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 62, 'Biện chứng là phương pháp:', '{"A":"Thấy cái chung mà không thấy cái riêng","B":"Thấy cái riêng mà không thấy cái chung","C":"Vừa thấy cái chung và cái riêng","D":"Thấy cái chung mà không thấy cái đơn nhất"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
