  ('MLN111', 64, 'Triết học Mác - Lênin ra đời một phần là kết quả kế thừa trực tiếp từ:', '{"A":"Thế giới quan duy vật của Hegel và phép biện chứng của Feuerbach","B":"Thế giới quan duy vật của Feuerbach và phép biện chứng của Hegel","C":"Thế giới quan duy vật và phép biện chứng của cả Hegel và Feuerbach","D":"Chủ nghĩa duy tâm của Holbach và phép biện chứng của Aristotle"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
