  ('MLN111', 106, 'Nội dung trước tiên của cách mạng xã hội chủ nghĩa là phải giành chính quyền về tay giai cấp công nhân và nhân dân lao động, đưa người lao động lên vị trí nào?', '{"A":"Thành người lao động tập thể","B":"Làm chủ tư liệu sản xuất","C":"Thành người quản lý xã hội","D":"Lên địa vị làm chủ xã hội"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
