  ('MLN111', 111, 'Theo quan điểm của chủ nghĩa duy vật lịch sử, trong kiến trúc thượng tầng của xã hội có giai cấp, yếu tố cơ bản nhất, có tác động trực tiếp và mạnh mẽ nhất tới cơ sở hạ tầng là yếu tố:', '{"A":"Tổ chức chính đảng","B":"Tổ chức nhà nước","C":"Tổ chức tôn giáo","D":"Các tổ chức văn hóa - xã hội"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 112, 'Trong mối quan hệ giữa lực lượng sản xuất và quan hệ sản xuất:', '{"A":"Lực lượng sản xuất là yếu tố thường xuyên biến đổi, phát triển","B":"Quan hệ sản xuất là yếu tố thường xuyên biến đổi, phát triển","C":"Cả hai đều là những yếu tố thường xuyên biến đổi, phát triển","D":"Không có yếu tố nào thường xuyên biến đổi, phát triển"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 113, 'Phương thức mà con người dùng để tiến hành quá trình sản xuất của xã hội ở những giai đoạn lịch sử nhất định là gì?', '{"A":"Phương thức sản xuất","B":"Nghệ thuật sản xuất","C":"Kỹ thuật sản xuất","D":"Công nghệ sản xuất"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 114, 'Theo quan niệm của chủ nghĩa duy vật lịch sử, yếu tố nào giữ vai trò đặc trưng cho chế độ kinh tế của một xã hội nhất định?', '{"A":"Quan hệ sản xuất mới","B":"Quan hệ sản xuất thống trị","C":"Quan hệ sản xuất mạnh nhất","D":"Quan hệ sản xuất đương thời"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 115, 'Theo chủ nghĩa duy vật lịch sử, khái niệm “cách mạng xã hội" dùng để chỉ:', '{"A":"Sự tiến bộ, tiến hóa mọi lĩnh vực trong một xã hội nhất định","B":"Sự thay thế chế độ xã hội này bằng một chế độ xã hội khác","C":"Sự thay thế thể chế kinh tế này bằng một thể chế kinh tế khác","D":"Sự thay thế hình thái kinh tế - xã hội này bằng hình thái kinh tế - xã hội khác cao hơn"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 116, 'Nhân tố đảm bảo cho sự thắng lợi cuối cùng của một chế độ xã hội là:', '{"A":"Có nhân tố nội tại","B":"Có nhân tố chính trị tiến bộ","C":"Có nền văn hóa tiên tiến, đậm đà bản sắc dân tộc","D":"Có thể tạo ra năng suất lao động cao hơn"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
