  ('MLN111', 135, 'Theo quan điểm triết học Mácxít, khẳng định nào sau đây sai?', '{"A":"Thế giới là một chỉnh thể trong sự liên hệ, ràng buộc lẫn nhau","B":"Con người không thể tách khỏi các mối quan hệ với tự nhiên","C":"Giữa các loài luôn có những khâu trung gian nối chúng với nhau","D":"Thế giới tinh thần và thế giới vật chất tồn tại độc lập nhau"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 136, 'Đâu là một khái quát của cách mạng xã hội?', '{"A":"Thay đổi thể chế chính trị xã hội này bằng thể chế chính trị khác","B":"Thay đổi thể chế kinh tế này bằng một thể chế kinh tế khác cao hơn","C":"Thay đổi căn bản, toàn diện và triệt để một hình thái kinh tế - xã hội này bằng một hình thái kinh tế - xã hội khác cao hơn","D":"Thay đổi hệ tư tưởng quản lý này bằng hệ tư tưởng quản lý khác"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 137, 'Theo quan điểm của chủ nghĩa duy vật lịch sử, cách mạng xã hội giữ vai trò gì?', '{"A":"Động lực phát triển của mọi xã hội","B":"Nguồn gốc và động lực tiến bộ của xã hội","C":"Phương thức, động lực cơ bản nhất của sự phát triển xã hội trong điều kiện xã hội có sự phân hóa thành đối kháng giai cấp","D":"Một trong những phương thức, động lực phát triển xã hội"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 138, 'Theo quan điểm của chủ nghĩa duy vật lịch sử, nhà nước là gì?', '{"A":"Tổ chức phi chính phủ","B":"Tổ chức quyền lực phi giai cấp","C":"Tổ chức quyền lực mang bản chất của giai cấp sở hữu tư liệu sản xuất chủ yếu của xã hội","D":"Tổ chức quyền lực mang bản chất của mọi giai cấp trong xã hội"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
