  ('MLN111', 179, 'Sự thống nhất giữa lực lượng sản xuất với một trình độ nhất định và quan hệ sản xuất tương ứng tạo thành gì?', '{"A":"Bản chất hàng hóa","B":"Năng lực sáng tạo","C":"Cách thức sản xuất","D":"Phương thức sản xuất"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 180, 'Nguồn gốc kinh tế của sự vận động và phát triển của hình thái kinh tế - xã hội là gì?', '{"A":"Mâu thuẫn giai cấp gay gắt trong xã hội có giai cấp","B":"Sự tăng lên không ngừng của năng suất lao động","C":"Mâu thuẫn giữa lực lượng sản xuất với quan hệ sản xuất","D":"Sự phát triển mạnh mẽ, đột phá của khoa học kỹ thuật công nghệ"}'::jsonb, 'C', 'C. Mâu thuẫn giữa lực lượng sản xuất với quan hệ sản xuất', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 181, 'Khái niệm nào chỉ sự quy định, sự tác động qua lại, sự chuyển hóa lẫn nhau giữa các sự vật, hiện tượng hay giữa các mặt, các yếu tố của chúng trong thê giới?', '{"A":"Mối liên hệ","B":"Mối liên hệ phổ biến","C":"Mối liên hệ phổ biến nhất","D":"Mối quan hệ"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 182, 'Vì các mối liên hệ có tính đa dạng, phong phú nên trong hoạt động nhận thức và thực tiễn khi thực hiện quan điểm toàn diện thì con người phải kết hợp với quan điểm:', '{"A":"Lịch sử - cụ thể","B":"Toàn diện","C":"Biện chứng","D":"Khách quan"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 183, 'Điều khẳng định nào sau đây là đúng?', '{"A":"Thuyết không thể biết không thừa nhận chân lý khách quan.","B":"Chủ nghĩa duy tâm chủ quan không thừa nhận chân lý khách quan.","C":"Chủ nghĩa duy tâm khách quan thừa nhận chân lý chủ quan.","D":"Chủ nghĩa duy vật biện chứng thừa nhận chân lý khách quan."}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 184, 'Luận điểm sau đây thuộc quan điểm triết học nào: "Phát triển là quá trình chuyên hóa từ những thay đổi về lượng thành sự thay đối về chất và ngược lại"?', '{"A":"Quan điểm chiết trung và ngụy biện","B":"Tất cả đều đúng","C":"Quan điểm biện chứng","D":"Quan điểm siêu hình"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 185, 'Các sự vật, hiện tượng khác nhau đều có những mối liên hệ cụ thể khác nhau, là biểu hiện của tính chất nào?', '{"A":"Đa dạng, phong phú","B":"Khách quan","C":"Phổ biến","D":"Chung nhất"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 186, 'Trước khi chủ nghĩa duy vật biện chứng ra đời, nhìn chung các nhà triết học duy vật quan niệm vật chất là gì?', '{"A":"Một hay một số chất tự có, đầu tiên","B":"Toàn bộ vật chất","C":"Vũ trụ quan","D":"Giới tự nhiên"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 187, 'Toàn bộ những chính sách, quan điểm, tư tưởng, đường lối chỉ đạo của nhà nước được gọi là gì?', '{"A":"Cơ sở hạ tầng","B":"Cơ sở thượng tầng","C":"Quan hệ sản xuất","D":"Kiến trúc thượng tầng"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 188, 'Đấu tranh giai cấp có vai trò gì đối với sự phát triển của xã hội có đối kháng giai cấp?', '{"A":"Kìm hãm sự phát triển của xã hội","B":"Tất cả đều sai","C":"Không có vai trò gì","D":"Là động lực thúc đẩy"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 189, 'Quan điểm phát triển đòi hỏi điều gì?', '{"A":"Bảo vệ cái mới, ủng hộ cái mới, đấu tranh cho cái mới nhưng không phủ định sạch trơn cái cũ","B":"Bảo vệ cái cũ, đấu tranh cho cái cũ đồng thời tạo điều kiện để cái mới ra đời và thay thế cái cũ","C":"Phát huy những mặt tích cực của cái cũ, tạo điều kiện cho nó phát triển","D":"Tạo điều kiện tiền đề cho cái mới phát triển"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 190, 'Chọn phương án trả lời phù hợp nhất: “Sự ra đời của Triết học Mác là một quá trình.............”. Từ còn thiếu trong chỗ trống là gì?', '{"A":"Tất yếu khách quan","B":"Thiết yếu","C":"\"nhiều hơn và đồ sộ hơn\"... “thế hệ trước\"","D":"Đấu tranh của giai cấp"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 191, 'Luận điểm sau thuộc lập trường triết học nào: Quy luật trong các khoa học là do sự sáng tạo của con người và được áp dụng vào tự nhiên và xã hội?', '{"A":"Chủ nghĩa duy vật siêu hình","B":"Chủ nghĩa duy tâm khách quan","C":"Chủ nghĩa duy vật biện chứng","D":"Chủ nghĩa duy tâm chủ quan"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 192, 'Chân lý bao gồm những tính chất nào? (Chọn các đáp án đúng)', '{"A":"Tính phong phú, đa dạng","B":"Tính khách quan","C":"Tính tương đối","D":"Tính cụ thể"}'::jsonb, 'B, C, D', 'B, C, D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 193, 'Một sinh viên tóm tắt nội dung quy luật về sự phù hợp giữa quan hệ sản xuất với trình độ của lực lượng sản xuất như sau. Đáp án nào sau đây là đúng?', '{"A":"Quy luật này vạch rõ sự phụ thuộc khách quan của lực lượng sản xuất vào quan hệ sản xuất","B":"Sự hình thành, biến đổi và phát triển của quan hệ sản xuất được quyết định bởi lực lượng sản xuất","C":"Lực lượng sản xuất và quan hệ sản xuất là hai mặt của phương thức sản xuất, chúng tồn tại tách rời nhau","D":"Quy luật này chỉ tồn tại trong một vài xã hội"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 194, 'Vị trí, vai trò của Triết học Mác - Lênin trong đời sống xã hội và trong sự nghiệp đổi mới ở Việt Nam hiện nay?', '{"A":"Thúc đẩy","B":"Đối lập","C":"Mâu thuẫn","D":"Quan trọng, là nền tảng tư tưởng, kim chỉ nam cho hành động"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 195, 'Theo quan điểm triết học Mác - Lênin, nhà nước có mấy đặc trưng?', '{"A":"Hai đặc trưng","B":"Ba đặc trưng","C":"Bốn đặc trưng","D":"Năm đặc trưng"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 196, 'Con chó, con mèo có ý thức không?', '{"A":"Có. Vì nó được con người dạy","B":"Không. Vì nó không được dạy","C":"Có. Vì nó được rèn luyện qua quá trình tiếp xúc với con người","D":"Không. Vì nó chỉ có bản năng"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 197, 'Chủ nghĩa duy vật lịch sử cho rằng sự ra đời, tồn tại của nhà nước là để duy trì trật tự xã hội trong điều kiện mâu thuẫn giai cấp như thế nào?', '{"A":"Đi đến giải quyết","B":"Phải được giải quyết","C":"Có thể giải quyết","D":"Không thể điều hòa được"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 198, 'Các hình thức tồn tại của các dạng cụ thể của vật chất ở một vị trí nhất định, có một quảng tính nhất định và tồn tại trong mối tương quan nhất định với các dạng cụ thể khác của vật chất được gọi là gì?', '{"A":"Tồn tại của vật chất","B":"Thời gian","C":"Không gian","D":"Sự tồn tại"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 199, 'Theo Lênin, khách quan là cái đang tồn tại:', '{"A":"Phụ thuộc nhận thức con người","B":"Trong thế giới con người","C":"Trong thế giới tự nhiên","D":"Độc lập, không phụ thuộc vào ý thức"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 200, 'Theo Triết học Mác, vật chất tồn tại thế nào?', '{"A":"Chủ quan","B":"Phụ thuộc vào con người","C":"Khách quan","D":"Theo ý muốn của thần linh"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 201, 'Ở Trung Quốc thời cổ đại có Triết học không?', '{"A":"Có","B":"Không","C":"Chỉ có hệ tư tưởng chứ không có triết học","D":"Không có hệ tư tưởng và triết học"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 202, 'Ý thức xã hội có tính chất nào sau đây?', '{"A":"Tính độc lập tương đối","B":"Tính độc lập tuyệt đối","C":"Tính sáng tạo","D":"Tính bất biến"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 203, 'Sự phát triển của các hình thái kinh tế - xã hội là quá trình như thế nào?', '{"A":"Quá trình phát triển của lịch sử tự nhiên","B":"Quá trình lịch sử hướng theo ý chí của giai cấp cầm quyền","C":"Quá trình lịch sử hướng theo ý chí của Đảng cầm quyền","D":"Quá trình lịch sử có chủ đích"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 204, 'Yếu tố chủ thể của lực lượng sản xuất là:', '{"A":"Con người với kỹ năng, kỹ xảo và tri thức được tích lũy lại","B":"Tư liệu sản xuất hiện đại","C":"Khoa học công nghệ tiên tiến","D":"Các phương án trả lời đều đúng"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 205, 'Trong nền sản xuất lớn hiện đại, yếu tố nào giữ vai trò quyết định năng suất của quá trình lao động sản xuất?', '{"A":"Sức lao động","B":"Tư liệu sản xuất hiện đại","C":"Công cụ sản xuất tiên tiến","D":"Đối tượng lao động"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 206, 'Theo sự phát triển của xã hội, thứ tự phát triển của các hình thức cộng đồng trong lịch sử là:', '{"A":"Thị tộc - Bộ lạc - Bộ tộc - Dân tộc","B":"Thị tộc - Bộ tộc - Bộ lạc - Dân tộc","C":"Dân tộc - Thị tộc - Bộ lạc - Bộ tộc","D":"Thị tộc - Bộ lạc - Dân tộc - Bộ tộc"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 207, 'Chọn câu trả lời sai. Trong một hình thái kinh tế xã hội, lực lượng sản xuất có các vai trò sau đây', '{"A":"Là nền tảng vật chất = kỹ thuật của xã hội","B":"Tiêu biểu cho bộ mặt xã hội ở mỗi giai đoạn phát triển","C":"Là nhân tố, xét đến cùng, quyết định sự hình thành và phát triển của mọi xã hội"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 208, 'Để tiến hành quá trình sản xuất vật chất, con người phải thiết lập nên các mối quan hệ với nhau, đó chính là các quan hệ:', '{"A":"Văn hoá","B":"Xã hội","C":"Chính trị","D":"Sản xuất"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 209, 'Trong mối quan hệ giữa "lực lượng sản xuất và quan hệ sản xuất”, yếu tố nào là nội dung, yếu tố nào là hình thức?', '{"A":"Lực lượng sản xuất là nội dung, quan hệ sản xuất là hình thức","B":"Quan hệ sản xuất là nội dung, lực lượng sản xuất là hình thức","C":"Lực lượng sản xuất và quan hệ sản xuất đều là nội dung","D":"Lực lượng sản xuất và quan hệ sản xuất đều là hình thức"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 210, 'Theo Lênin, vật chất có mấy hình thức tồn tại?', '{"A":"1","B":"2","C":"3","D":"4"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 211, 'Trong xã hội có giai cấp, nội dung và hình thức phát triển của ý thức xã hội khác nhau do đâu?', '{"A":"Những điều kiện sinh hoạt vật chất, lợi ích và địa vị của các giai cấp khác nhau","B":"Thói quen khác nhau","C":"Sở thích khác nhau","D":"Những điều kiện sinh hoạt tinh thần, địa vị, thói quen của các giai cấp khác nhau"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 212, 'Nguyên nhân là một phạm trù triết học chỉ cái gì?', '{"A":"Tác động qua lại giữa các mặt, các yếu tố bên trong sự vật hay giữa sự vật này với sự vật kia tạo ra những biến đổi nhất định","B":"Quan hệ giữa các mặt, các yếu tố bên trong sự vật hay giữa sự vật này với sự vật kia tạo ra những biến đổi nhất định","C":"Sự chuyển hóa giữa các mặt, các yếu tố bên trong sự vật hay giữa sự vật này với sự vật kia tạo ra những biến đổi nhất định","D":"Chỉ những cái có trước và luôn luôn quyết định cái sau"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 213, 'Theo quan điểm của triết học Mác - Lênin, tiêu chí cơ bản để đánh giá phẩm chất của mỗi cá nhân là gì?', '{"A":"Địa vị xã hội và tài sản","B":"Thái độ, hành vi đạo đức của cá nhân","C":"Sự thực hiện khả năng làm chủ đối với hoàn cảnh và hành động thực tiễn của cá nhân","D":"Tất cả đều đúng"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 214, 'Theo quan điểm của chủ nghĩa Mác - Lênin, khái niệm nào dùng để chỉ lực lượng sản xuất cơ bản của xã hội, trực tiếp sản xuất ra của cải vật chất, là cơ sở của sự tồn tại và phát triển của xã hội, là động lực cơ bản của mọi cuộc cách mạng xã hội và là người sáng tạo ra những giá trị văn hóa tinh thần cho xã hội?', '{"A":"Quần chúng nhân dân","B":"Giai cấp nông dân","C":"Lãnh tụ","D":"Vĩ nhân"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 215, 'Theo học thuyết Mác, chủ nghĩa nào về cơ bản là đúng vì nó đã lấy giới tự nhiên để giải thích giới tự nhiên, không viện đến Thần linh như cách giải thích của tôn giáo?', '{"A":"Duy tâm khách quan","B":"Duy vật biện chứng","C":"Duy vật siêu hình","D":"Duy vật chất phác"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 216, 'Theo quan điểm của chủ nghĩa duy tâm khách quan, mối quan hệ giữa các sự vật do cái gì quyết định?', '{"A":"Lực lượng siêu nhiên (thượng đế, ý niệm tuyệt đối)","B":"Cảm giác, thói quen của con người","C":"Bản chất của thế giới tự nhiên","D":"Phức hợp của cảm giác"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 217, 'Theo quan niệm của chủ nghĩa duy vật biện chứng về lịch sử thì trong xã hội có giai cấp, hệ tư tưởng thống trị xã hội bao giờ cũng là hệ tư tưởng của giai cấp:', '{"A":"Tiên tiến nhất","B":"Lãnh đạo xã hội","C":"Thống trị xã hội","D":"Đứng đầu xã hội"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 218, 'Ai là người đã đưa ra định nghĩa về giai cấp sau đây: "Người ta gọi là giai cấp, những tập đoàn to lớn gồm những người khác nhau về địa vị của họ trong một hệ thống sản xuất xã hội nhất định trong lịch sử, khác nhau về quan hệ của họ (thường thường thì những quan hệ này được pháp luật quy định và thừa nhận) đối với tư liệu sản xuất, về vai trò của họ trong tổ chức lao động xã hội và như vậy là khác nhau về cách thức hưởng thụ và về phần của cải xã hội ít hoặc nhiều mà họ được hưởng. Giai cấp là những tập đoàn người, mà tập đoàn này thì có thể chiếm đoạt lao động của tập đoàn khác, do chỗ tập đoàn đó có địa vị khác nhau trong một chế độ kinh tế - xã hội nhất định"?', '{"A":"Heraclit","B":"Khổng Tử","C":"V.I. Lênin","D":"Chủ tịch Hồ Chí Minh"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 219, 'Theo quan điểm của chủ nghĩa Mác - Lênin, "Bộ lạc” được định nghĩa là gì?', '{"A":"Là cộng đồng bao gồm những bộ lạc có quan hệ cùng huyết thống hoặc các thị tộc có quan hệ hôn nhân liên kết với nhau","B":"Là cộng đồng bao gồm những thị tộc có quan hệ hôn nhân liên kết với nhau","C":"Là cộng đồng bao gồm những thị tộc có quan hệ cùng huyết thống hoặc các thị tộc có quan hệ hôn nhân liên kết với nhau","D":"Là cộng đồng bao gồm những thị tộc có quan hệ cùng huyết thống"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 220, 'Triết học trở thành nữ tì của thần học trong giai đoạn nào?', '{"A":"Ở Tây Âu thời trung cổ","B":"Ở Tây Âu thời cổ đại","C":"Ở Tây Âu thời cận đại","D":"Ở Châu Âu thời hiện đại"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 221, 'Ai là người tạo ra cơ sở tri thức cho sự phát triển của triết học trong thời kỳ Phục hưng?', '{"A":"Adam Smith","B":"Martin Luther","C":"Saint-Simon","D":"Copernicus"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 222, 'Triết học phổ biến ở Tây Âu thời Trung cổ là Triết học gì?', '{"A":"Triết học tự nhiên","B":"Triết học kinh viện","C":"Triết học khoa học xã hội","D":"Triết học chính trị"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 223, 'Trong chủ nghĩa Mác - Lênin thì', '{"A":"Triết học là cơ sở nên tảng của kinh tế chính trị và chủ nghĩa xã hội khoa học","B":"Kinh tế chính trị học là cơ sở nền tảng của triết học và chủ nghĩa xã hội khoa học","C":"Chủ nghĩa xã hội khoa học là cơ sở của kinh tế chính trị và triết học"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 224, '“Cân bằng động” trong sự phù hợp giữa lực lượng sản xuất và quan hệ sản xuất là gì?', '{"A":"Lực lượng sản xuất và quan hệ sản xuất phù hợp trong suốt quá trình phát triển của con người","B":"Lực lượng sản xuất thay đổi, quan hệ sản xuất không cần thay đổi","C":"Sự phù hợp cụ thể nào đó giữa quan hệ sản xuất và lực lượng sản xuất luôn bị phá vỡ để thay bằng một sự phù hợp khác cao hơn","D":"Khi lực lượng sản xuất đã đến lúc cần thay đổi thì nhất định là quan hệ sản xuất cũng sẽ thay đổi"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 225, 'Cơ sở của sự tồn tại và phát triển của xã hội là sản xuất nào?', '{"A":"Sản xuất tinh thần","B":"Sản xuất con người","C":"Sản xuất văn hóa","D":"Sản xuất vật chất"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 226, 'Bản chất của nhà nước là gì?', '{"A":"Cơ quan trọng tài thực hiện chức năng phân xử và hòa giải các xung đột xã hội","B":"Công cụ của giai cấp thống trị xã hội","C":"Công cụ của giai cấp bị trị"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 227, 'Dân chủ được hiểu là gì?', '{"A":"Một giá trị xã hội phản ánh các quyền cơ bản của con người; là một hình thức tổ chức nhà nước của giai cấp cầm quyền; có quá trình ra đời, phát triển cùng với lịch sử xã hội nhân loại","B":"Một giá trị xã hội phản ánh các quyền cơ bản của con người; là một hình thức tổ chức nhà nước của giai cấp tư sản cầm quyền; có quá trình ra đời, phát triển cùng với lịch sử xã hội nhân loại","C":"Một giá trị xã hội phản ánh các quyền cơ bản của con người; là một hình thức tổ chức nhà nước của giai cấp thống trị cầm quyền; có quá trình ra đời, phát triển từ xã hội chiếm hữu nô lệ","D":"Một giá trị xã hội phản ánh các quyền cơ bản của con người; là một hình thức tổ chức nhà nước của giai cấp vô sản cầm quyền; có quá trình ra đời, phát triển cùng với lịch sử xã hội nhân loại"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 228, 'Đâu là một trong những tác phẩm của Lênin?', '{"A":"Chủ nghĩa xã hội không tưởng Pháp","B":"Chủ nghĩa duy vật và chủ nghĩa kinh viện phê phán","C":"Chủ nghĩa duy vật và chủ nghĩa kinh nghiệm phê phán","D":"Đường Kách mệnh"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 229, 'Đâu là một trong những trường phái của triết học duy tâm?', '{"A":"Duy tâm khách quan","B":"Duy tâm duy lý","C":"Duy tâm biện chứng","D":"Duy tâm tôn giáo"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 230, 'Cái bàn, cái ghế có phải là vật chất với tư cách là một phạm trù triết học hay không?', '{"A":"Có. Vì nó là dạng của vật chất trong không gian.","B":"Không. Vì nó không có vật chất trong không gian.","C":"Có. Vì nó có tồn tại cụ thể, có kích thước và tồn tại cùng thời gian.","D":"Không. Vì nó chỉ là một dạng cụ thể của vật chất."}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 231, 'Theo quan điểm của triết học Mác - Lênin, thuộc tính phản ánh là thuộc tính có ở đối tượng nào?', '{"A":"Riêng có ở con người","B":"Chỉ có ở các cơ thể sống","C":"Chỉ có ở các chất vô cơ","D":"Phổ biến ở mọi tổ chức vật chất"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 232, 'Hoạt động sản xuất vật chất là cơ sở hình thành nên quan hệ gì?', '{"A":"Quan hệ kinh tế giữa người với người","B":"Quan hệ vật chất giữa người với người","C":"Quan hệ kinh tế - vật chất giữa người với vật","D":"Quan hệ kinh tế - vật chất giữa người với người"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 233, 'Tâm lý, tính cách tiểu nông của người Việt Nam truyền thống căn bản là do những yếu tố nào quy định? (Chọn các đáp án đúng)', '{"A":"Bản tính cố hữu của người Việt Nam","B":"Bị phong kiến, để quốc nhiều thế kỷ áp bức thống trị","C":"Phương thức sản xuất tiểu nông, lạc hậu tồn tại lâu dài trong lịch sử","D":"Điều kiện tổ chức dân cư khép kín của các làng xã"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 234, 'Biểu tượng, tình cảm, tâm trạng của quần chúng về tín ngưỡng, tôn giáo tạo thành bộ phận nào?', '{"A":"Tâm lý tôn giáo","B":"Tổ chức tôn giáo","C":"Hành vi tôn giáo","D":"Hệ tư tưởng tôn giáo"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 235, 'Tính chất kế thừa của ý thức xã hội làm cho nó có tính chất nào sau đây?', '{"A":"Tính phản ánh hư ảo","B":"Tính phê phán","C":"Tính độc lập tương đối","D":"Tính hiện thực"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 236, 'Chủ nghĩa duy vật lịch sử cho rằng, ý thức lý luận đạt trình độ cao và mang tính hệ thống tạo thành cái gì?', '{"A":"Hệ tư tưởng","B":"Hệ kiến thức","C":"Tri thức tổng hợp","D":"Hệ thống tri thức"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 237, 'Theo quan điểm của chủ nghĩa duy vật lịch sử, loài người đã và đang trải qua bao nhiêu hình thái kinh tế - xã hội?', '{"A":"Ba hình thái kinh tế - xã hội","B":"Bốn hình thái kinh tế - xã hội","C":"Năm hình thái kinh tế - xã hội","D":"Sáu hình thái kinh tế - xã hội"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 238, 'Theo triết học Mác, sự chuyển dịch từ hình thái kinh tế chiếm hữu nô lệ, sang phong kiến rồi đến xã hội chủ nghĩa thuộc loại vận động nào?', '{"A":"Vận động vật lý","B":"Vận động hóa học","C":"Vận động sinh học","D":"Vận động xã hội"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 239, 'Đâu là cơ sở hình thành nên quan hệ kinh tế - vật chất giữa người với người?', '{"A":"Hoạt động chính trị, xã hội","B":"Hoạt động thực nghiệm khoa học","C":"Hoạt động sản xuất vật chất"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 240, 'Theo quan điểm của chủ nghĩa Mác - Lênin, kiến trúc thượng tầng là gì?', '{"A":"Toàn bộ thiết chế chính trị của xã hội","B":"Toàn bộ thiết chế chính trị và pháp luật của xã hội","C":"Toàn bộ quan hệ sản xuất hợp thành cơ cấu kinh tế và các thiết chế chính trị - xã hội tương ứng","D":"Toàn bộ hệ thống kết cấu các hình thái ý thức xã hội cùng với các thiết chế chính trị - xã hội tương ứng"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 241, 'Theo triết học Mác - Lênin, yếu tố nào đóng vai trò quyết định đối với tất cả các mặt của đời sống xã hội?', '{"A":"Khoa học","B":"Phương thức sản xuất","C":"Chính trị","D":"Văn hóa nghệ thuật"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 242, 'Luận điểm cho rằng "vật hay vật thể là những phức hợp cảm giác" thuộc trường phái triết học nào?', '{"A":"Chủ nghĩa duy tâm chủ quan.","B":"Chủ nghĩa duy tâm khách quan.","C":"Chủ nghĩa duy vật siêu hình.","D":"Tất cả các đáp án đều đúng."}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 243, 'Cái do nguyên nhân cơ bản bên trong của kết cấu vật chất quyết định và trong những điều kiện nhất định nó phải xảy ra như thế chứ không thể khác được gọi là gì?', '{"A":"Tất nhiên","B":"Ngẫu nhiên","C":"Hệ quả","D":"Bản chất"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 244, 'Vị trí của quy luật phủ định của phủ định trong phép biện chứng duy vật:', '{"A":"Chỉ ra cách thức của sự phát triển","B":"Chỉ ra nguồn gốc của sự phát triển","C":"Chỉ ra nguyên nhân của sự phát triển","D":"Chỉ ra khuynh hướng của sự phát triển"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 245, 'Ai là người không chỉ khác phương pháp của Hêghen về cơ bản mà còn đối lập hẳn?', '{"A":"Feuerbach","B":"Ph. Ăngghen","C":"V. I. Lênin","D":"C. Mác"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 246, 'Quan điểm nào cho rằng sự phát triển chỉ là sự tăng, giảm đơn thuần về mặt lượng, không có sự thay đổi về chất?', '{"A":"Quan điểm duy vật","B":"Quan điểm duy tâm","C":"Quan điểm siêu hình","D":"[Không có]"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 247, 'Quan điểm ủng hộ cái mới tiến bộ, từ đó chống lại cái cũ, cái lỗi thời kìm hãm sự phát triển là quan điểm được rút ra trực tiếp từ quy luật nào?', '{"A":"Quy luật từ những thay đổi về lượng dẫn đến những thay đổi về chất và ngược lại","B":"Quy luật thống nhất và đấu tranh của các mặt đối lập","C":"Quy luật phủ định của phủ định","D":"Quy luật biện chứng của lực lượng sản xuất và quan hệ sản xuất"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 248, '"... là mối liên hệ tất nhiên, tương đối ổn định bên trong sự vật, quy định sự vận động và phát triển của sự vật." Điền vào chỗ trống:', '{"A":"Hiện tượng","B":"Bản chất","C":"Nội dung","D":"Hình thức"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 249, 'Chủ nghĩa duy vật biện chứng khẳng định rằng, nguyên nhân sinh ra kết quả phải có thêm yếu tố nào?', '{"A":"Tác động","B":"Điều kiện","C":"Nguyên cớ","D":"Ý chí"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 250, 'Theo triết học Mác, con người là gì?', '{"A":"Thực thể sinh học - xã hội","B":"Thực thể tự nhiên - sinh học","C":"Kết hợp con vật và con người","D":"Là thực thể do thánh thần tạo ra"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
