  ('MLN111', 252, 'Theo quan điểm của triết học Mác - Lênin, tiêu chí cơ bản để đánh giá phẩm chất của mỗi cá nhân là gì?', '{"A":"Địa vị xã hội của cá nhân","B":"Thái độ, hành vi đạo đức của cá nhân","C":"Sự thực hiện khả năng làm chủ đối với hoàn cảnh và hành động thực tiễn của cá nhân","D":"Tất cả đều đúng"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 253, 'Triết học có mấy vấn đề CƠ BẢN? Trong vấn đề cơ bản đó có mấy mặt?', '{"A":"1 mặt, 2 vấn đề","B":"1 vấn đề, 1 mặt","C":"1 vấn đề, 2 mặt","D":"2 mặt, 2 vấn đề"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 254, 'Cơ sở để phân chia triết học thành các trường phái khác nhau là:', '{"A":"Vấn đề cơ bản của nhận thức luận","B":"Vấn đề cơ bản của phương pháp luận","C":"Vấn đề cơ bản của triết học","D":"[Không có]"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 255, 'A là một sinh viên có học lực kém, nên gia đình và Thầy/Cô đã khuyến A nên cố gắng nhiều hơn nữa. Nhận thấy được vấn đề, A đã ra sức học tập để tích lũy kiến thức. Trải qua một khoảng thời gian, bạn A không chỉ trở thành một học sinh giỏi mà còn đạt được học bổng do Đại học FPT cấp. Căn cứ vào kiến thức được học ở môn Triết học, Anh/Chị hãy cho biết trường hợp bạn A thuộc 1 trong 3 quy luật nào sau đây?', '{"A":"Quy luật từ những sự thay đổi về lượng dẫn đến sự thay đổi về chất và ngược lại","B":"Quy luật thống nhất và đấu tranh giữa các mặt đối lập","C":"Quy luật phủ định của phủ định","D":"Quy luật phát triển"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 256, 'Mặt thứ nhất trong vấn đề cơ bản của triết học giải quyết mối quan hệ giữa các yếu tố nào sau đây?', '{"A":"Tư duy với thực tế","B":"Tư duy với xã hội","C":"Ý thức và vật chất","D":"Ý thức và bộ não"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 257, 'Tổng thể các quan hệ sản xuất của một xã hội trong sự vận động hiện thực của chúng hợp thành cơ cấu nào sau đây?', '{"A":"Cơ sở hạ tầng","B":"Cơ sở thượng tầng","C":"Quan hệ sản xuất","D":"Quan hệ phân phối"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 258, 'Theo quan điểm của chủ nghĩa duy vật lịch sử thì do khác nhau và đối lập nhau về yếu tố nào tạo ra khả năng khách quan dẫn đến tập đoàn này có thể chiếm đoạt lao động của tập đoàn khác?', '{"A":"Quyền lực","B":"Sở hữu","C":"Địa vị","D":"Tài sản"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 259, 'Lơxíp (khoảng 500 - 440 trước CN) được xem là?', '{"A":"Nhà triết học Giáo hội Cổ đại","B":"Nhà toán học Hy Lạp Cổ đại","C":"Nhà triết học Hy Lạp Cổ đại","D":"Nhà thần học Hy Lạp Cổ đại"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 260, 'Vận dụng triết học vào thực tế, ta không dựa trên quan điểm nào?', '{"A":"Lịch sử cụ thể","B":"Phát triển","C":"Kế thừa","D":"Duy tâm"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 261, 'Nhận định nào sau đây là sai khi nói về vị trí, vai trò của Triết học Mác - Lênin trong đời sống xã hội và trong sự nghiệp đổi mới ở Việt Nam hiện nay?', '{"A":"Là thế giới quan khoa học cho hoạt động thực tiễn","B":"Là phương pháp luận biện chứng cho nhận thức khoa học","C":"Là chìa khóa vạn năng để giải quyết mọi vấn đề","D":"Là nền tảng tư tưởng, kim chỉ nam cho hành động"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 262, 'Theo quan điểm của chủ nghĩa duy vật biện chứng về mối quan hệ giữa tất nhiên và ngẫu nhiên, trong hoạt động thực tiễn, cần dựa vào điều gì?', '{"A":"Dựa vào ngẫu nhiên, dự phòng tất nhiên.","B":"Dựa vào ngẫu nhiên, đề phòng tất nhiên","C":"Dựa vảo cả tất nhiên và ngẫu nhiên","D":"Không dựa vào các yếu tố nào mang tính tất nhiên, ngẫu nhiên"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 263, 'Hình thức hoạt động thực tiễn cơ bản nhất quyết định các hình thức hoạt động khác là hình thức nào sau đây?', '{"A":"Hoạt động chính trị - xã hội","B":"Hoạt động quan sát và thực nghiệm khoa học","C":"Hoạt động sản xuất vật chất","D":"Hoạt động kinh tế"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 264, 'Một sinh viên chuẩn bị bài seminar trong 1 tuần theo cách thức: ngày đầu phác thảo đề cương sơ lược sau đó hàng ngày dành 15 phút sửa chữa và bổ sung bài chuẩn bị đó cả kết cấu, nội dung. Đúng vào buổi seminar, sinh viên đó đã có một bản chuẩn bị hoàn chỉnh. Công việc trên đã diễn ra theo nguyên lý, quy luật nào?', '{"A":"Quy luật mâu thuẫn","B":"Quy luật lượng - chất","C":"Quy luật phủ định của phủ định","D":"Nguyên lý về mối liên hệ phổ biến"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 265, 'Nguồn gốc trực tiếp của sự ra đời giai cấp trong xã hội?', '{"A":"Do sự phát triển lực lượng sản xuất làm xuất hiện “của dư\" tương đối","B":"Do sự chênh lệch về khả năng giữa các tập đoàn người","C":"Do sự phân hóa giữa giàu và nghèo trong xã hội","D":"Do sự xuất hiện của tư hữu về tư liệu sản xuất"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 266, 'Chỉ có một thế giới duy nhất là thế giới vật chất là thể hiện tính chất gì của thế giới vật chất?', '{"A":"Đa dạng","B":"Thống nhất","C":"Tổng hợp","D":"Đặc thù"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 267, 'Theo quan điểm của Triết học Mác - Lênin, ý thức là hình ảnh chủ quan của yếu tố nào sau đây?', '{"A":"Tinh thần tuyệt đối","B":"Thế giới khách quan","C":"Bộ óc con người","D":"Ý niệm tuyệt đối"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 268, 'Một trong các nội dung định nghĩa của Lênin về vật chất đó là: vật chất được cảm giác của chúng ta chép lại, chụp lại, phản ánh và tồn tại như thế nào?', '{"A":"Lệ thuộc vào cảm giác","B":"Không lệ thuộc vào cảm giác","C":"Tuỳ thuộc vào nhận thức","D":"Tuỳ theo ý thức"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 269, 'Trong mối quan hệ với tồn tại xã hội, ý thức xã hội có tính chất nào sau đây?', '{"A":"Tính độc lập tương đối","B":"Tính độc lập tuyệt đối","C":"Tính sáng tạo","D":"Tính bất biến"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 270, 'Theo V.I. Lênin "Chủ nghĩa Mác đã mở đường cho việc nghiên cứu rộng rãi và toàn diện quá trình phát sinh, phát triển và suy tàn của...', '{"A":"Hệ thống vật chất trong giới tự nhiên","B":"Các quá trình kinh tế và chính trị - xã hội","C":"Các sự vật, hiện tượng trong thế giới tự nhiên, xã hội và tư duy","D":"Các hình thái kinh tế - xã hội"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 271, 'Ai là người khẳng định: “cái sự hiển nhiên là trước hết con người cần phải ăn, uống, ở và mặc, nghĩa là phải lao động, trước khi có thể đấu tranh để giành quyền thống trị, trước khi có thể hoạt động chính trị, tôn giáo, triết học”?', '{"A":"C. Mác","B":"Ph. Ăngghen","C":"Platon","D":"Immanuel Kant"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 272, 'Hình thức sản xuất nào sau đây có vai trò quyết định sự tồn tại và phát triển của xã hội?', '{"A":"Sản xuất vật chất","B":"Sản xuất tinh thần","C":"Sản xuất con người","D":"Sản xuất xã hội"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 273, 'Bộ phận nào của tư liệu lao động được coi là tiêu chí phản ánh đặc trưng phát triển của một thời đại kinh tế?', '{"A":"Công cụ lao động","B":"Kết cấu hạ tầng sản xuất","C":"Nhà cửa, kho bãi ... để chứa đựng, bảo quản","D":"Quan hệ sản xuất"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 274, 'Mối quan hệ giữa cơ sở hạ tầng và kiến trúc thượng tầng là mối quan hệ như thế nào?', '{"A":"Luôn luôn thống nhất với nhau","B":"Luôn luôn đối lập nhau","C":"Thống nhất và đấu tranh giữa hai mặt đối lập","D":"Thống nhất là căn bản, còn đấu tranh giữa chúng chỉ là tạm thời"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 275, 'Theo quan điểm của chủ nghĩa duy vật lịch sử, mỗi hình thái kinh tế - xã hội được cấu thành từ những nhân tố nào?', '{"A":"Lực lượng sản xuất, kiến trúc thượng tầng","B":"Quan hệ kinh tế, lực lượng sản xuất và kiến trúc thượng tầng","C":"Quan hệ sản xuất và kiến trúc thượng tầng","D":"Lực lượng sản xuất, quan hệ sản xuất hợp thành cơ cấu kinh tế của xã hội và kiến trúc thượng tầng"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 276, 'Học thuyết Hình thái kinh tế - xã hội là nội dung của trường phái nào?', '{"A":"Chủ nghĩa duy tâm khách quan","B":"Chủ nghĩa duy tâm lịch sử","C":"Chủ nghĩa duy vật biện chứng","D":"Chủ nghĩa duy vật lịch sử"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 277, 'Ai là người khẳng định: “Cần phải có sự phân biệt rõ ràng giữa vật chất với tính cách là một phạm trù của triết học”?', '{"A":"G. Mác","B":"Ph. Ăngghen","C":"L. Feuerbach","D":"Immanuel Kant"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 278, 'Cái tất nhiên là cái do:', '{"A":"Những nguyên nhân cơ bản bên trong sự vật quy định","B":"Những nguyên nhân bên ngoài sự vật quy định","C":"Cả nguyên nhân bên trong và nguyên nhân bên ngoài sự vật quy định","D":"Những nguyên nhân bản chất bên trong quy định"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 279, 'Theo quan điểm của phép biện chứng duy vật thì phạm trù chỉ một sự vật, một hiện tượng, một quá trình nhất định là:', '{"A":"Đặc thù","B":"Bản chất","C":"Cái riêng","D":"Hiện tượng"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
