  ('MLN111', 281, 'Theo quan điểm duy vật biện chứng, nguyên nhân và kết quả có thể...', '{"A":"chuyển hóa lẫn nhau.","B":"tồn tại độc lập với nhau.","C":"xuất hiện đồng thời.","D":"không có mối liên hệ qua lại."}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 282, 'Theo quan điểm của chủ nghĩa duy vật lịch sử, điều kiện nào sau đây là tiên quyết, cần thiết và chủ yếu quyết định sự hình thành và phát triển của con người cả về phương diện sinh học và xã hội?', '{"A":"Lao động","B":"Ngôn ngữ","C":"Văn hóa","D":"Giao tiếp"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 283, 'Triết học của các nhà tư tưởng thời kỳ Phục Hưng có đặc điểm gì?', '{"A":"Có tính chất duy vật tự phát","B":"Có tính chất duy tâm khách quan","C":"Còn pha trộn giữa các yếu tố duy vật và duy tâm","D":"Còn pha trộn giữa các yếu tố duy tâm thần bí và siêu hình"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 284, 'Triết học nào sau đây cho rằng tinh thần khách quan có trước, tồn tại độc lập với giới tự nhiên và quyết định giới tự nhiên?', '{"A":"Duy vật thô sơ","B":"Duy ý chí","C":"Duy tâm chủ quan","D":"Duy tâm khách quan"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 285, 'Biện chứng là phương pháp xem xét thế giới trong trạng thái nào?', '{"A":"Bất động, bất biến","B":"Luôn vận động, biến đổi và phát triển không ngừng","C":"Đứng im","D":"Không ngừng thay đổi"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 286, 'Trong chủ nghĩa Mác - Lênin, bộ phận lý luận nào có chức năng làm sáng tỏ bản chất và những quy luật chung nhất của mọi sự vận động, phát triển của thế giới?', '{"A":"Triết học Mác - Lênin","B":"Kinh tế chính trị Mác - Lênin","C":"Chủ nghĩa xã hội khoa học","D":"Không có bộ phận nào giữ chức năng đó vì chủ nghĩa Mác - Lênin thuộc khoa học xã hội"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 287, 'Triết học Mác - Lênin ra đời một phần là kết quả kế thừa trực tiếp từ đâu?', '{"A":"Thế giới quan duy vật của Hegel và phép biện chứng của Feuerbach","B":"Thế giới quan duy vật của Feuerbach và phép biện chứng của Hegel","C":"Thế giới quan duy vật và phép biện chứng của cả Hegel và Feuerbach","D":"Chủ nghĩa duy tâm của Hegel và biện chứng pháp của Aristốt"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 288, 'Cơ sở của sự tồn tại và phát triển xã hội có nguồn gốc trực tiếp từ đâu?', '{"A":"Nền tảng xã hội","B":"Sản xuất vật chất","C":"Thế giới vật chất","D":"Thế giới khách quan"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 289, 'Khi V.I. Lênin phát triển chủ nghĩa Mác trong giai đoạn đế quốc chủ nghĩa, ông đã bổ sung lý luận nào cho phù hợp với bối cảnh xã hội mới?', '{"A":"Khả năng của cách mạng vô sản chỉ có thể xảy ra đồng thời trên toàn cầu","B":"Khả năng cách mạng vô sản có thể xảy ra ở một hoặc một số nước có điều kiện thích hợp","C":"Chủ nghĩa đế quốc là giai đoạn phát triển cao nhất và là giai đoạn suy tàn của chủ nghĩa tư bản","D":"Chủ nghĩa đế quốc phát triển sẽ làm giảm căng thẳng giữa các quốc gia tư bản, từ đó ổn định xã hội"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 290, 'Theo Mác và Ph. Ăngghen, để tồn tại và phát triển, con người cần phải thực hiện hoạt động gì?', '{"A":"Vận động","B":"Làm giàu","C":"Sản xuất","D":"Kinh doanh"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 291, 'Theo chủ nghĩa duy vật lịch sử, các chính sách và pháp luật của nhà nước suy đến cùng chỉ là phản ánh nhu cầu thống trị về kinh tế của giai cấp nắm giữ yếu tố nào của xã hội?', '{"A":"Lực lượng sản xuất chủ yếu của xã hội","B":"Quyền tổ chức-quản lý xã hội","C":"Nhà nước","D":"Quyền sở hữu các tư liệu sản xuất chủ yếu"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 292, 'Chọn đáp án đúng điền vào chỗ trống: Sự ra đời và tồn tại của nhà nước .....', '{"A":"là hiện tượng mang tính khách quan, được quyết định bởi quá trình phát triển của xã hội.","B":"là hiện tượng mang tính chủ quan, phụ thuộc vào nguyện vọng của giai cấp cầm quyền.","C":"là hiện tượng mang tính chủ quan phụ thuộc vào nguyện vọng của mỗi quốc gia, mỗi dân tộc.","D":"là hiện tượng mang tính khách quan, được quy định bởi sự phát triển của khoa học kỹ thuật."}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 293, 'Theo cách phân chia các hình thức vận động của Ph. Ăngghen, hình thức vận động nào là thấp nhất?', '{"A":"Hình thức vận động cơ học","B":"Hình thức vận động vật lý","C":"Hình thức vận động hóa học","D":"Hình thức vận động xã hội"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 294, 'Ngũ hành gồm những yếu tố nào?', '{"A":"Kim, mộc, thổ, thủy, không khí","B":"Kim, mộc, thủy, hỏa, lễ","C":"Kim, mộc, thủy, hỏa, thổ"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 295, 'Theo quan điểm của triết học Mác - Lênin, luận điểm nào sau đây chưa chính xác khi đề cập đến mối quan hệ giữa tồn tại xã hội và ý thức xã hội?', '{"A":"Một bộ phận ý thức xã hội có thể vượt trước tồn tại xã hội","B":"Ý thức xã hội mang tính kế thừa","C":"Ý thức xã hội luôn thay đổi ngay lập tức khi tồn tại xã hội thay đổi","D":"Ý thức xã hội thường lạc hậu, bảo thủ so với tồn tại xã hội"}'::jsonb, 'C', 'C', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 296, 'Loại hình hoạt động thực tiễn nhằm mục đích cải biến các đối tượng của giới tự nhiên theo nhu cầu tồn tại và phát triển của con người và xã hội là gì?', '{"A":"Khoa học","B":"Sản xuất vật chất","C":"Thực nghiệm khoa học","D":"Nghiên cứu khoa học"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 297, 'Theo triết học Mác, hình thái kinh tế - xã hội cuối cùng là?', '{"A":"Phong kiến","B":"Tư bản chủ nghĩa","C":"Xã hội chủ nghĩa","D":"Cộng sản chủ nghĩa"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 298, 'Khái niệm quan hệ sản xuất được hiểu như thế nào?', '{"A":"Mối quan hệ giữa con người với giới tự nhiên","B":"Tổng hợp các quan hệ kinh tế giữa con người với con người trong quá trình sản xuất vật chất","C":"Mối quan hệ giữa con người với con người trong quá trình lao động","D":"Mối quan hệ kinh tế trong quá trình sản xuất và tái sản xuất của xã hội"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 299, '"Thông thường, trong kiến trúc thượng tầng các nhà nước tư bản hiện nay như thế nào?', '{"A":"Đều thực hiện chế độ nhất nguyên chính trị","B":"Không thực hiện chế độ đa nguyên chính trị","C":"Tùy từng nước mà có thể thực hiện chế độ đa nguyên chính trị hay không","D":"Thực hiện chế độ đa đảng nhưng nhất nguyên chính trị"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 300, 'Cấu trúc của phương thức sản xuất gồm những yếu tố nào sau đây?', '{"A":"Trình độ lao động, quan hệ sản xuất","B":"Lực lượng sản xuất, quan hệ sản xuất","C":"Tư liệu sản xuất và con người"}'::jsonb, 'B', 'B', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 301, 'Vị trí của quy luật phủ định trong phép biện chứng duy vật là gì?', '{"A":"Chỉ ra cách thức của sự phát triển","B":"Ghi ra nguồn gốc của sự phát triển","C":"Chỉ ra nguyên nhân của sự phát triển","D":"Chỉ ra khuynh hướng của sự phát triển"}'::jsonb, 'D', 'D', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 302, 'Nguyên nhân và kết quả, cái nào có trước?', '{"A":"Nguyên nhân","B":"Kết quả","C":"Cả hai cũng xuất hiện trước","D":"Không cái nào xuất hiện trước"}'::jsonb, 'A', 'A Nguyên nhân (nguyên nhân bao giờ cũng có trước kết quả về mặt thời gian)', '[]'::jsonb, true, false, 'low', null),
  ('MLN111', 303, 'Quan điểm lịch sử cụ thể được rút ra từ nghiên cứu nguyên lý triết học nào sau đây?', '{"A":"Nguyên lý về mối liên hệ phổ biến","B":"Nguyên lý phát triển","C":"Nguyên lý triết học thực hành"}'::jsonb, 'A', 'A', '[]'::jsonb, true, false, 'low', null),
