  ('MLN122', 1, 'Trường phái kinh tế chính trị nào xuất hiện đầu tiên trong thời kỳ từ cổ đại đến cuối thế kỷ XVII?', '{"A":"Trường phái trọng thương","B":"Trường phái trọng nông","C":"Kinh tế chính trị tư sản cổ điển","D":"Kinh tế chính trị Mác - Lênin"}'::jsonb, 'A', 'Trọng thương là trường phái kinh tế chính trị xuất hiện sớm, gắn với thời kỳ thương nghiệp phát triển.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 2, 'Đối tượng nghiên cứu chủ yếu của trường phái trọng thương là gì?', '{"A":"Lưu thông hàng hóa và tiền tệ","B":"Nông nghiệp","C":"Sản xuất công nghiệp","D":"Tiêu dùng cá nhân"}'::jsonb, 'A', 'Trọng thương chú trọng lĩnh vực lưu thông, đặc biệt là tiền tệ và thương mại.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 3, 'Trường phái trọng thương đặc biệt coi trọng lĩnh vực nào?', '{"A":"Ngoại thương","B":"Nông nghiệp","C":"Sản xuất thủ công","D":"Tiêu dùng"}'::jsonb, 'A', 'Trọng thương cho rằng làm giàu chủ yếu thông qua ngoại thương và tích lũy tiền.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 4, 'Trường phái trọng nông chủ yếu nghiên cứu lĩnh vực nào?', '{"A":"Nông nghiệp","B":"Ngoại thương","C":"Công nghiệp nặng","D":"Tài chính ngân hàng"}'::jsonb, 'A', 'Trọng nông cho rằng nông nghiệp là ngành sản xuất tạo ra của cải chủ yếu.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 5, 'Chủ nghĩa trọng nông hình thành và phát triển mạnh ở quốc gia nào?', '{"A":"Pháp","B":"Anh","C":"Đức","D":"Mỹ"}'::jsonb, 'A', 'Chủ nghĩa trọng nông là trường phái kinh tế tiêu biểu ở Pháp.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 6, 'Kinh tế chính trị Mác - Lênin kế thừa trực tiếp từ trường phái nào?', '{"A":"Kinh tế chính trị tư sản cổ điển Anh","B":"Chủ nghĩa trọng thương","C":"Chủ nghĩa trọng nông","D":"Kinh tế học hiện đại"}'::jsonb, 'A', 'Mác kế thừa có phê phán những thành tựu của kinh tế chính trị tư sản cổ điển Anh.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 7, 'Lịch sử phát triển của nền sản xuất xã hội có hai kiểu tổ chức kinh tế cơ bản nào?', '{"A":"Sản xuất tự cấp tự túc và sản xuất hàng hóa","B":"Sản xuất nhỏ và sản xuất lớn","C":"Sản xuất nông nghiệp và sản xuất công nghiệp","D":"Sản xuất tư nhân và sản xuất nhà nước"}'::jsonb, 'A', 'Hai kiểu tổ chức kinh tế cơ bản là sản xuất tự cấp tự túc và sản xuất hàng hóa.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 8, 'Sản xuất tự cấp tự túc là kiểu sản xuất mà sản phẩm làm ra nhằm mục đích gì?', '{"A":"Để người sản xuất tự tiêu dùng là chính","B":"Để bán trên thị trường là chính","C":"Để xuất khẩu","D":"Để tích lũy tư bản"}'::jsonb, 'A', 'Sản xuất tự cấp tự túc phục vụ trực tiếp nhu cầu của chính người sản xuất.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 9, 'Sản xuất hàng hóa là gì?', '{"A":"Kiểu tổ chức kinh tế mà sản phẩm được sản xuất ra để trao đổi, mua bán trên thị trường","B":"Kiểu sản xuất chỉ phục vụ gia đình người sản xuất","C":"Kiểu sản xuất không có phân công lao động","D":"Kiểu sản xuất không cần thị trường"}'::jsonb, 'A', 'Sản xuất hàng hóa tạo ra sản phẩm nhằm đáp ứng nhu cầu người khác thông qua trao đổi, mua bán.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 10, 'Giá trị của hàng hóa được tạo ra ở đâu?', '{"A":"Trong sản xuất","B":"Trong phân phối","C":"Trong lưu thông","D":"Trong tiêu dùng"}'::jsonb, 'A', 'Giá trị hàng hóa do lao động xã hội của người sản xuất kết tinh trong quá trình sản xuất.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 11, 'Điều kiện ra đời của sản xuất hàng hóa gồm những yếu tố nào?', '{"A":"Phân công lao động xã hội và sự tách biệt tương đối về kinh tế giữa những người sản xuất","B":"Chỉ cần có tiền tệ","C":"Chỉ cần có nhà nước","D":"Chỉ cần có thị trường chứng khoán"}'::jsonb, 'A', 'Sản xuất hàng hóa ra đời khi có phân công lao động xã hội và các chủ thể sản xuất độc lập tương đối.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 12, 'Sự tách biệt tương đối về kinh tế giữa những người sản xuất thường do yếu tố nào quyết định?', '{"A":"Quan hệ sở hữu khác nhau về tư liệu sản xuất","B":"Sở thích cá nhân giống nhau","C":"Thời tiết thay đổi","D":"Dân số giảm"}'::jsonb, 'A', 'Sự khác nhau về sở hữu tư liệu sản xuất làm người sản xuất độc lập với nhau về kinh tế.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 13, 'Sản xuất hàng hóa tạo ra sản phẩm chủ yếu để làm gì?', '{"A":"Trao đổi, mua bán","B":"Tự dùng trong gia đình","C":"Cất giữ lâu dài","D":"Biếu tặng không điều kiện"}'::jsonb, 'A', 'Đặc điểm của sản xuất hàng hóa là sản phẩm được làm ra để trao đổi trên thị trường.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 14, 'Hàng hóa là gì?', '{"A":"Sản phẩm của lao động, có thể thỏa mãn nhu cầu nào đó của con người và dùng để trao đổi, mua bán","B":"Mọi vật có trong tự nhiên","C":"Mọi thứ con người thích","D":"Chỉ là tiền vàng"}'::jsonb, 'A', 'Hàng hóa phải là sản phẩm lao động, có ích và được đưa vào trao đổi.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 15, 'Hàng hóa có thể tồn tại dưới những dạng nào?', '{"A":"Hữu hình và vô hình","B":"Chỉ hữu hình","C":"Chỉ vô hình","D":"Chỉ dạng vật chất rắn"}'::jsonb, 'A', 'Hàng hóa có thể là vật phẩm hữu hình hoặc dịch vụ vô hình.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 16, 'Theo quan điểm của C. Mác, hàng hóa có hai thuộc tính nào?', '{"A":"Giá trị sử dụng và giá trị","B":"Giá cả và thương hiệu","C":"Lợi nhuận và tiền lương","D":"Cung và cầu"}'::jsonb, 'A', 'Hai thuộc tính cơ bản của hàng hóa là giá trị sử dụng và giá trị.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 17, 'Giá trị sử dụng của hàng hóa do yếu tố nào tạo thành?', '{"A":"Thuộc tính tự nhiên của vật phẩm","B":"Tên gọi của hàng hóa","C":"Giá bán trên thị trường","D":"Số lượng người mua"}'::jsonb, 'A', 'Công dụng của hàng hóa xuất phát từ các thuộc tính tự nhiên của nó.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 18, 'Kinh tế hàng hóa phát triển qua hai giai đoạn cơ bản nào?', '{"A":"Kinh tế hàng hóa giản đơn và kinh tế thị trường","B":"Kinh tế nông nghiệp và kinh tế tự cấp","C":"Kinh tế đóng và kinh tế bao cấp","D":"Kinh tế tự nhiên và kinh tế gia đình"}'::jsonb, 'A', 'Kinh tế hàng hóa phát triển từ hình thức giản đơn đến kinh tế thị trường.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 19, 'Cặp phạm trù nào là phát hiện riêng của C. Mác khi phân tích hàng hóa?', '{"A":"Lao động cụ thể và lao động trừu tượng","B":"Lao động giản đơn và lao động phức tạp","C":"Lao động quá khứ và lao động sống","D":"Lao động tư nhân và lao động xã hội"}'::jsonb, 'A', 'Mác phát hiện tính hai mặt của lao động sản xuất hàng hóa: cụ thể và trừu tượng.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 20, 'Lao động cụ thể là gì?', '{"A":"Lao động có ích dưới một hình thức cụ thể của một nghề nhất định","B":"Lao động không cần kỹ năng","C":"Lao động giống nhau trong mọi ngành","D":"Lao động chỉ tạo ra tiền"}'::jsonb, 'A', 'Lao động cụ thể tạo ra giá trị sử dụng với hình thức nghề nghiệp nhất định.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 21, 'Lao động giản đơn là gì?', '{"A":"Lao động không cần qua đào tạo, huấn luyện chuyên môn","B":"Lao động phức tạp nhất","C":"Lao động chỉ có trong nông nghiệp","D":"Lao động chỉ tạo ra giá trị thặng dư"}'::jsonb, 'A', 'Lao động giản đơn là lao động bình thường, không cần đào tạo chuyên môn đặc biệt.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 22, 'Khi năng suất lao động tăng, số lượng sản phẩm sản xuất ra trong một đơn vị thời gian sẽ thế nào?', '{"A":"Tăng lên","B":"Giảm xuống","C":"Không đổi","D":"Biến mất"}'::jsonb, 'A', 'Năng suất lao động tăng làm tạo ra nhiều sản phẩm hơn trong cùng thời gian.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 23, 'Khi năng suất lao động tăng, giá trị của một đơn vị hàng hóa sẽ thế nào?', '{"A":"Giảm xuống","B":"Tăng lên","C":"Không đổi trong mọi trường hợp","D":"Bằng không"}'::jsonb, 'A', 'Cùng một thời gian lao động tạo ra nhiều sản phẩm hơn nên giá trị mỗi sản phẩm giảm.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 24, 'Hình thái biểu hiện của giá trị phát triển qua mấy hình thái cơ bản?', '{"A":"4 hình thái","B":"3 hình thái","C":"2 hình thái","D":"1 hình thái"}'::jsonb, 'A', 'Giá trị phát triển qua bốn hình thái, từ giản đơn đến tiền tệ.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 25, 'Bản chất của tiền tệ là gì?', '{"A":"Một hàng hóa đặc biệt đóng vai trò vật ngang giá chung","B":"Một tờ giấy không có giá trị","C":"Chỉ là phương tiện trang trí","D":"Một loại dịch vụ"}'::jsonb, 'A', 'Tiền tệ là hàng hóa đặc biệt được xã hội thừa nhận làm vật ngang giá chung.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 26, 'Tiền tệ có mấy chức năng cơ bản?', '{"A":"5 chức năng","B":"4 chức năng","C":"3 chức năng","D":"2 chức năng"}'::jsonb, 'A', 'Tiền tệ có 5 chức năng cơ bản trong kinh tế hàng hóa.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 27, 'Chức năng nào của tiền tệ đòi hỏi tiền phải là tiền vàng hoặc tiền có giá trị đầy đủ?', '{"A":"Phương tiện cất trữ","B":"Phương tiện thanh toán","C":"Phương tiện lưu thông","D":"Thước đo giá trị"}'::jsonb, 'A', 'Cất trữ đòi hỏi tiền có giá trị thực, điển hình là vàng.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 28, 'Quá trình sản xuất là sự kết hợp của những yếu tố nào?', '{"A":"Lao động với đối tượng lao động và tư liệu lao động","B":"Tiền với ngân hàng","C":"Cầu với giá cả","D":"Lợi nhuận với lãi suất"}'::jsonb, 'A', 'Sản xuất diễn ra khi lao động tác động vào đối tượng lao động thông qua tư liệu lao động.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 29, 'Trong tư liệu lao động, bộ phận nào quyết định trực tiếp đến năng suất lao động?', '{"A":"Công cụ lao động","B":"Kho chứa hàng","C":"Đường giao thông","D":"Nhà xưởng phụ"}'::jsonb, 'A', 'Công cụ lao động là yếu tố tác động trực tiếp đến năng suất.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 30, 'Sản phẩm cuối cùng của lưu thông hàng hóa giản đơn là gì?', '{"A":"Giá trị sử dụng","B":"Tiền","C":"Giá trị thặng dư","D":"Lợi nhuận"}'::jsonb, 'A', 'Trong lưu thông giản đơn H - T - H, mục đích cuối cùng là giá trị sử dụng.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 31, 'Công thức lưu thông hàng hóa giản đơn là gì?', '{"A":"H - T - H","B":"T - H - T''","C":"T - T''","D":"H - H - T"}'::jsonb, 'A', 'Lưu thông hàng hóa giản đơn bắt đầu bằng bán hàng lấy tiền rồi mua hàng khác.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 32, 'Công thức chung của tư bản là gì?', '{"A":"T - H - T''","B":"H - T - H","C":"H - H - T","D":"T - T - H"}'::jsonb, 'A', 'Tư bản vận động theo công thức tiền ứng ra mua hàng hóa rồi thu về tiền lớn hơn.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 33, 'Mâu thuẫn công thức chung của tư bản được giải quyết nhờ hàng hóa đặc biệt nào?', '{"A":"Sức lao động","B":"Vàng","C":"Máy móc","D":"Đất đai"}'::jsonb, 'A', 'Sức lao động là hàng hóa đặc biệt có khả năng tạo ra giá trị lớn hơn giá trị của nó.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 34, 'Theo C. Mác, sức lao động là gì?', '{"A":"Toàn bộ thể lực, trí lực và kinh nghiệm tồn tại trong con người được sử dụng trong sản xuất","B":"Chỉ là cơ bắp của người lao động","C":"Chỉ là máy móc trong nhà xưởng","D":"Chỉ là tiền lương"}'::jsonb, 'A', 'Sức lao động là năng lực lao động của con người được đem ra sử dụng trong sản xuất.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 35, 'Hàng hóa sức lao động tạo ra cái gì trong lưu thông tư bản?', '{"A":"Giá trị thặng dư","B":"Chỉ tạo ra tiền lương","C":"Chỉ tạo ra hàng tồn kho","D":"Chỉ tạo ra thuế"}'::jsonb, 'A', 'Khi được sử dụng trong sản xuất, sức lao động tạo ra giá trị mới lớn hơn giá trị của nó.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 36, 'Sức lao động trở thành hàng hóa khi có mấy điều kiện cơ bản?', '{"A":"2 điều kiện","B":"3 điều kiện","C":"4 điều kiện","D":"1 điều kiện"}'::jsonb, 'A', 'Người lao động phải tự do về thân thể và không có tư liệu sản xuất để tự sản xuất.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 37, 'Chế độ xã hội nào đầu tiên phổ biến việc sử dụng sức lao động thành hàng hóa?', '{"A":"Chủ nghĩa tư bản","B":"Xã hội phong kiến","C":"Xã hội cộng sản nguyên thủy","D":"Xã hội chiếm hữu nô lệ"}'::jsonb, 'A', 'Trong chủ nghĩa tư bản, sức lao động trở thành hàng hóa phổ biến.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 38, 'Hình thức nào sau đây không phải là biểu hiện trực tiếp của giá trị thặng dư?', '{"A":"Tiền lương","B":"Lợi nhuận","C":"Lợi tức","D":"Địa tô"}'::jsonb, 'A', 'Tiền lương là hình thức biểu hiện giá trị sức lao động, không phải giá trị thặng dư.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 39, 'Tư bản bất biến được ký hiệu là gì?', '{"A":"c","B":"v","C":"m","D":"p"}'::jsonb, 'A', 'Tư bản bất biến được ký hiệu là c.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 40, 'Tư bản khả biến được ký hiệu là gì?', '{"A":"v","B":"c","C":"m","D":"k"}'::jsonb, 'A', 'Tư bản khả biến được ký hiệu là v.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 41, 'Loại tư bản nào trực tiếp sinh ra giá trị thặng dư?', '{"A":"Tư bản khả biến","B":"Tư bản bất biến","C":"Tư bản cố định","D":"Tư bản cho vay"}'::jsonb, 'A', 'Tư bản khả biến dùng để mua sức lao động, nguồn tạo ra giá trị thặng dư.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 42, 'Khủng hoảng kinh tế trong chủ nghĩa tư bản thường trải qua các giai đoạn nào?', '{"A":"Khủng hoảng - tiêu điều - phục hồi - hưng thịnh","B":"Phục hồi - khủng hoảng - hưng thịnh - tiêu điều","C":"Hưng thịnh - phục hồi - tiêu điều - khủng hoảng","D":"Tiêu điều - hưng thịnh - khủng hoảng - phục hồi"}'::jsonb, 'A', 'Chu kỳ khủng hoảng thường gồm: khủng hoảng, tiêu điều, phục hồi, hưng thịnh.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 43, 'Theo C. Mác, có mấy phương pháp sản xuất giá trị thặng dư?', '{"A":"2 phương pháp","B":"3 phương pháp","C":"4 phương pháp","D":"1 phương pháp"}'::jsonb, 'A', 'Có hai phương pháp: sản xuất giá trị thặng dư tuyệt đối và tương đối.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 44, 'Hai phương pháp sản xuất giá trị thặng dư là gì?', '{"A":"Sản xuất giá trị thặng dư tuyệt đối và sản xuất giá trị thặng dư tương đối","B":"Sản xuất tự cấp và sản xuất hàng hóa","C":"Sản xuất nông nghiệp và công nghiệp","D":"Sản xuất giản đơn và tiêu dùng"}'::jsonb, 'A', 'Mác chỉ ra hai cách cơ bản để tạo giá trị thặng dư: tuyệt đối và tương đối.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 45, 'Tái sản xuất gồm những hình thức cơ bản nào?', '{"A":"Tái sản xuất giản đơn và tái sản xuất mở rộng","B":"Sản xuất tự nhiên và sản xuất gia đình","C":"Sản xuất hàng hóa và tiêu dùng","D":"Sản xuất tiền tệ và tín dụng"}'::jsonb, 'A', 'Tái sản xuất có hai hình thức chính: giản đơn và mở rộng.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 46, 'Có mấy nhân tố cơ bản ảnh hưởng đến quy mô tích lũy tư bản?', '{"A":"4 nhân tố","B":"3 nhân tố","C":"2 nhân tố","D":"1 nhân tố"}'::jsonb, 'A', 'Quy mô tích lũy tư bản chịu ảnh hưởng của nhiều yếu tố, thường nêu thành 4 nhân tố cơ bản.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 47, 'Cấu tạo hữu cơ của tư bản gồm những mặt nào?', '{"A":"Cấu tạo kỹ thuật và cấu tạo giá trị","B":"Tiền lương và giá cả","C":"Cung và cầu","D":"Lợi nhuận và lợi tức"}'::jsonb, 'A', 'Cấu tạo hữu cơ của tư bản phản ánh mối liên hệ giữa cấu tạo kỹ thuật và cấu tạo giá trị.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 48, 'Về mặt giá trị, cấu tạo tư bản được chia thành gì?', '{"A":"Tư bản bất biến và tư bản khả biến","B":"Lợi tức và địa tô","C":"Tiền lương và giá cả","D":"Hàng hóa và tiền tệ"}'::jsonb, 'A', 'Về giá trị, tư bản gồm c là tư bản bất biến và v là tư bản khả biến.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 49, 'Chi phí sản xuất tư bản chủ nghĩa k gồm những bộ phận nào?', '{"A":"c + v","B":"c + m","C":"v + m","D":"c + v + m"}'::jsonb, 'A', 'Chi phí sản xuất tư bản chủ nghĩa là phần tư bản ứng ra gồm c và v.', '[]'::jsonb, true, false, 'low', null),
  ('MLN122', 50, 'Về lượng, chi phí sản xuất tư bản chủ nghĩa k so với giá trị hàng hóa như thế nào?', '{"A":"Nhỏ hơn giá trị hàng hóa","B":"Bằng giá trị hàng hóa","C":"Lớn hơn giá trị hàng hóa","D":"Bằng giá trị thặng dư"}'::jsonb, 'A', 'Giá trị hàng hóa là c + v + m, còn k = c + v nên k nhỏ hơn giá trị hàng hóa.', '[]'::jsonb, true, false, 'low', null)
